/* /product_matrix/static/src/js/matrix_configurator_hook.js */
odoo.define('@product_matrix/js/matrix_configurator_hook', ['@web/core/utils/hooks', '@product_matrix/js/product_matrix_dialog'], function(require) {
    'use strict';
    let __exports = {};
    const {useService} = require("@web/core/utils/hooks");
    const {ProductMatrixDialog} = require("@product_matrix/js/product_matrix_dialog");
    __exports.useMatrixConfigurator = useMatrixConfigurator;
    function useMatrixConfigurator() {
        const dialog = useService("dialog");
        const openDialog = (rootRecord, jsonInfo, productTemplateId, editedCellAttributes) => {
            const infos = JSON.parse(jsonInfo);
            dialog.add(ProductMatrixDialog, {
                header: infos.header,
                rows: infos.matrix,
                editedCellAttributes: editedCellAttributes.toString(),
                product_template_id: productTemplateId,
                record: rootRecord,
            });
        }
        ;
        const open = async (record, edit) => {
            const rootRecord = record.model.root;
            await rootRecord.update({
                grid_product_tmpl_id: record.data.product_template_id,
            });
            const updatedLineAttributes = [];
            if (edit) {
                for (const ptnvav of record.data.product_no_variant_attribute_value_ids.records) {
                    updatedLineAttributes.push(ptnvav.resId);
                }
                for (const ptav of record.data.product_template_attribute_value_ids.records) {
                    updatedLineAttributes.push(ptav.resId);
                }
                updatedLineAttributes.sort( (a, b) => a - b);
            }
            openDialog(rootRecord, rootRecord.data.grid, record.data.product_template_id.id, updatedLineAttributes);
            if (!edit) {
                rootRecord.data.order_line.delete(record);
            }
        }
        ;
        return {
            open
        };
    }
    return __exports;
});
;
/* /product_matrix/static/src/js/product_matrix_dialog.js */
odoo.define('@product_matrix/js/product_matrix_dialog', ['@web/core/dialog/dialog', '@web/views/fields/formatters', '@web/core/hotkeys/hotkey_hook', '@odoo/owl'], function(require) {
    'use strict';
    let __exports = {};
    const {Dialog} = require('@web/core/dialog/dialog');
    const {formatMonetary} = require("@web/views/fields/formatters");
    const {useHotkey} = require("@web/core/hotkeys/hotkey_hook");
    const {Component, onMounted, markup, useRef} = require("@odoo/owl");
    const ProductMatrixDialog = __exports.ProductMatrixDialog = class ProductMatrixDialog extends Component {
        static template = "product_matrix.dialog";
        static props = {
            header: {
                type: Object
            },
            rows: {
                type: Object
            },
            editedCellAttributes: {
                type: String
            },
            product_template_id: {
                type: Number
            },
            record: {
                type: Object
            },
            close: {
                type: Function
            },
        };
        static components = {
            Dialog
        };
        setup() {
            this.size = 'xl';
            const productMatrixRef = useRef('productMatrix');
            useHotkey("enter", () => this._onConfirm(), {
                bypassEditableProtection: true,
                area: () => productMatrixRef.el,
            });
            onMounted( () => {
                if (this.props.editedCellAttributes.length) {
                    const inputs = document.getElementsByClassName('o_matrix_input');
                    const relevantInput = Array.from(inputs).filter( (matrixInput) => matrixInput.attributes.ptav_ids.nodeValue === this.props.editedCellAttributes)[0];
                    if (relevantInput) {
                        relevantInput.select();
                    } else {
                        inputs[0].select();
                    }
                } else {
                    document.getElementsByClassName('o_matrix_input')[0].select();
                }
            }
            );
        }
        _format({price, currency_id}) {
            if (!price) {
                return "";
            }
            const sign = price < 0 ? '-' : '+';
            const formatted = formatMonetary(Math.abs(price), {
                currencyId: currency_id,
            }, );
            return markup(`&nbsp;${sign}&nbsp;${formatted}&nbsp;`);
        }
        _onConfirm() {
            const inputs = document.getElementsByClassName('o_matrix_input');
            let matrixChanges = [];
            for (let matrixInput of inputs) {
                if (matrixInput.value && matrixInput.value !== matrixInput.attributes.value.nodeValue) {
                    matrixChanges.push({
                        qty: parseFloat(matrixInput.value),
                        ptav_ids: matrixInput.attributes.ptav_ids.nodeValue.split(",").map(id => parseInt(id)),
                    });
                }
            }
            if (matrixChanges.length > 0) {
                this.props.record.update({
                    grid: JSON.stringify({
                        changes: matrixChanges,
                        product_template_id: this.props.product_template_id
                    }),
                    grid_update: true
                });
            }
            this.props.close();
        }
    }
    return __exports;
});
;
