    registerTemplate("mail.CreatePollDialog", `/mail/static/src/core/common/create_poll_dialog.xml`, `<t t-name="mail.CreatePollDialog" xml:space="preserve">
    <Dialog size="'md'" title.translate="Create a poll">
        <div class="w-100 mb-3">
            <label class="w-100">
                <span class="d-inline-block mb-2 fw-bold">Question</span>
                <input type="text" name="poll_question" t-model="state.question" class="form-control rounded" placeholder="What question do you want to ask?" t-ref="question"/>
                <div t-if="questionMissing" class="text-danger form-text ms-1">The question cannot be empty.</div>
            </label>
        </div>
        <div class="mb-3">
            <span class="mb-2 d-inline-block fw-bold">Options</span>
            <CreatePollOptionDialog t-foreach="state.options" t-as="option" t-key="option_index" model="option" deletable="state.options.length &gt; 2" onClickRemove="() =&gt; this.onClickRemoveOption(option_index)"/>
            <button class="btn btn-link align-self-end" t-on-click="onClickAddOption"><i class="fa fa-plus me-1"/> Add another option</button>
            <div t-if="optionsMissing" class="text-danger form-text ms-1">At least two options are required</div>
        </div>
        <div class="d-flex justify-content-between gap-3">
            <label class="d-flex align-items-center">
                <span class="fw-bold me-2">Allow multiple options</span>
                <input type="checkbox" name="poll_allow_multiple_options" t-model="state.allowMultipleOptions"/>
            </label>
            <label class="d-flex align-items-center">
                <span class="fw-bold me-2">Duration</span>
                <select class="form-select" name="poll_duration" style="width: fit-content;" t-model="state.duration">
                    <option value="10">10 minutes</option>
                    <option value="60">1 hour</option>
                    <option value="240">4 hours</option>
                    <option value="480">8 hours</option>
                    <option value="1440">24 hours</option>
                </select>
        </label>
        </div>
        <t t-set-slot="footer">
            <button class="btn btn-primary me-2" t-on-click="onClickSubmit">Post</button>
            <button class="btn btn-secondary me-2" t-on-click="props.close">Cancel</button>
        </t>
    </Dialog>
</t>
`);
    registerTemplate("mail.CreatePollOptionDialog", `/mail/static/src/core/common/create_poll_option_dialog.xml`, `<t t-name="mail.CreatePollOptionDialog" xml:space="preserve">
        <div class="o-mail-CreatePollOptionDialog d-flex gap-2 mb-3">
            <div class=" input-group">
                <button class="btn btn-outline-secondary" type="button" t-ref="picker"><i class="fa fa-lg fa-smile-o"/></button>
                <input type="text" t-model="props.model.label" class="form-control rounded" placeholder="Type your option" t-ref="root"/>
            </div>
            <button t-if="props.deletable" class="btn btn-primary" title="Delete option" t-on-click="props.onClickRemove"><i class="fa fa-trash"/></button>
        </div>
    </t>
`);
    registerTemplate("mail.DateSection", `/mail/static/src/core/common/date_section.xml`, `<t t-name="mail.DateSection" xml:space="preserve">
    <div class="o-mail-DateSection d-flex align-items-center w-100 fw-bold z-1" t-attf-class="{{ props.className }}">
        <hr class="o-discuss-separator flex-grow-1"/>
        <span class="px-2 smaller text-muted opacity-50" t-att-class="{ 'user-select-none': isMobileOS }"><t t-esc="props.date"/></span>
        <hr class="o-discuss-separator flex-grow-1"/>
    </div>
</t>
`);
    registerTemplate("mail.Gif", `/mail/static/src/core/common/gif.xml`, `<t t-name="mail.Gif" xml:space="preserve">
       <img t-att-src="props.paused and state.snapshot ? state.snapshot : props.src" t-att-loading="props.loading" t-att-data-paused="props.paused" t-att-alt="props.alt" t-att-class="props.class" t-att-style="props.style" t-on-click="() =&gt; props.onClick?.()" t-on-load="onLoad"/>
    </t>
`);
    registerTemplate("mail.ImStatus", `/mail/static/src/core/common/im_status.xml`, `<t t-name="mail.ImStatus" xml:space="preserve">
        <div class="o-mail-ImStatus d-flex justify-content-center flex-shrink-0 align-items-center bg-white bg-opacity-100" t-attf-class="{{ props.className }}" t-att-style="props.style" t-att-class="{             'o-md': props.size === 'md' or props.size === 'medium',             'o-sm': props.size === 'sm' or props.size === 'small',             'rounded-circle': !showTypingIndicator,             'rounded-pill': showTypingIndicator,         }">
            <span class="d-flex flex-column" t-att-class="{                 'smaller': props.size === 'md' or props.size === 'medium',                 'o-xsmaller': props.size === 'sm' or props.size === 'small',             }">
                <t t-slot="pre_icon"/>
                <t name="icon">
                    <t t-if="(!props.member or !showTypingIndicator) and persona">
                        <i t-if="persona.im_status === 'online'" class="fa fa-circle text-success" title="Online" role="img" aria-label="User is online"/>
                        <i t-elif="persona.im_status === 'away'" class="fa fa-adjust o-yellow" title="Idle" role="img" aria-label="User is idle"/>
                        <i t-elif="persona.im_status === 'busy'" class="fa fa-minus-circle text-danger" title="Busy" role="img" aria-label="User is busy"/>
                        <i t-elif="persona.im_status === 'offline'" class="fa fa-circle-o text-700 opacity-75" title="Offline" role="img" aria-label="User is offline"/>
                        <i t-elif="persona.im_status === 'bot'" class="fa fa-heart text-success" title="Bot" role="img" aria-label="User is a bot"/>
                        <i t-else="" class="fa fa-question-circle opacity-75" title="No IM status available"/>
                    </t>
                    <div t-if="showTypingIndicator" class="rounded-pill" style="padding: 1px;" t-att-class="{ 'bg-300': env.inChatBubble, 'bg-inherit': !env.inChatBubble }">
                        <div class="bg-success rounded-pill" style="padding: 3px;">
                            <Typing member="props.member" size="['sm', 'smaller'].includes(props.size) ? 'sm' : 'md'" displayText="false"/>
                        </div>
                    </div>
                </t>
            </span>
        </div>
    </t>

`);
    registerTemplate("mail.ImStatusDropdown", `/mail/static/src/core/common/im_status_dropdown.xml`, `<t t-name="mail.ImStatusDropdown" xml:space="preserve">
        <Dropdown menuClass="'o-mail-ImStatusDropdown'">
            <a href="#" t-att-class="{ 'd-block text-body py-3 fs-4 d-flex flex-row gap-2': env.isSmall }"><ImStatus persona="store.self"/> <span t-esc="readableImStatus"/> <i t-if="env.isSmall" class="oi oi-chevron-right ms-auto mt-1"/></a>
            <t t-set-slot="content">
                <DropdownItem class="{ 'active': this.store.self.im_status.includes('online') }" onSelected="() =&gt; this.setManualImStatus('online')"><i class="fa fa-circle text-success me-1" title="Online" role="img"/> Online</DropdownItem>
                <hr class="my-1"/>
                <DropdownItem class="{ 'active': this.store.self.im_status.includes('away') }" onSelected="() =&gt; this.setManualImStatus('away')"><i class="fa fa-adjust o-yellow me-1" title="Away" role="img"/> Away</DropdownItem>
                <DropdownItem class="{ 'active': this.store.self.im_status.includes('busy') }" onSelected="() =&gt; this.setManualImStatus('busy')">
                    <i class="fa fa-minus-circle text-danger me-1" title="Busy" role="img"/> Do Not Disturb
                    <div class="small text-muted">You will not receive any notifications</div>
                </DropdownItem>
                <DropdownItem class="{ 'active': this.store.self.im_status.includes('offline') }" onSelected="() =&gt; this.setManualImStatus('offline')"><i class="fa fa-circle-o text-700 opacity-75 me-1" title="Offline" role="img"/> Offline</DropdownItem>
            </t>
        </Dropdown>
    </t>
`);
    registerTemplate("mail.LinkPreview", `/mail/static/src/core/common/link_preview.xml`, `<t t-name="mail.LinkPreview" xml:space="preserve">
        <t t-if="linkPreview.isCard" t-call="mail.LinkPreviewCard"/>
        <t t-if="linkPreview.isVideo" t-call="mail.LinkPreviewVideo"/>
        <t t-if="linkPreview.isImage" t-call="mail.LinkPreviewImage"/>
    </t>

    `);
    registerTemplate("mail.LinkPreviewCard", `/mail/static/src/core/common/link_preview.xml`, `<t t-name="mail.LinkPreviewCard" xml:space="preserve">
        <div class="o-mail-LinkPreviewCard card position-relative w-100 mb-2 rounded bg-view shadow-sm overflow-hidden" t-att-class="{ 'me-2': env.inChatter }" t-attf-class="{{ className }}">
            <div class="row g-0 flex-row-reverse h-100">
                <div class="col min-w-0" t-att-class="{ 'd-flex align-items-center': !linkPreview.og_description }">
                    <div class="px-3 py-2">
                        <h6 class="card-title mb-0 me-2" t-attf-class="{{ linkPreview.og_description ? 'text-truncate' : 'overflow-hidden' }}">
                            <a t-att-href="linkPreview.source_url" target="_blank" t-out="linkPreview.og_title"/>
                        </h6>
                        <span t-if="linkPreview.og_site_name" t-out="linkPreview.og_site_name"/>
                        <p t-if="linkPreview.og_description" class="o-mail-LinkPreviewCard-description card-text mb-0 mt-2 text-muted small overflow-hidden" t-out="linkPreview.og_description"/>
                    </div>
                </div>
                <div class="o-mail-LinkPreviewCard-imageLinkWrap col-4 d-block">
                    <a t-att-href="linkPreview.source_url" target="_blank">
                        <img t-if="linkPreview.og_image" class="w-100 h-100 object-fit-cover" t-att-src="linkPreview.og_image" t-att-alt="linkPreview.og_title" t-on-load="onImageLoaded"/>
                        <span t-else="" class="d-flex align-items-center justify-content-center w-100 h-100 bg-100 text-300">
                            <i class="fa fa-camera fa-2x"/>
                        </span>
                    </a>
                </div>
            </div>
            <t t-call="mail.LinkPreview.aside">
                <t t-set="className" t-value="'fa fa-stack p-0 opacity-75 opacity-100-hover'"/>
            </t>
        </div>
    </t>

    `);
    registerTemplate("mail.LinkPreviewImage", `/mail/static/src/core/common/link_preview.xml`, `<t t-name="mail.LinkPreviewImage" xml:space="preserve">
        <div class="o-mail-LinkPreviewImage position-relative mb-2 rounded" t-att-class="{ 'me-2': env.inChatter }" t-attf-class="{{ className }}">
            <a t-if="linkPreview.imageUrl" t-att-href="linkPreview.imageUrl" target="_blank">
                <Gif t-if="linkPreview.isGif" paused="props.messageLinkPreview.gifPaused" class="'h-auto w-auto rounded'" src="linkPreview.imageUrl" onLoad.bind="onImageLoaded"/>
                <img t-else="" class="h-auto w-auto rounded" t-att-src="linkPreview.imageUrl" t-on-load="onImageLoaded"/>
            </a>
            <t t-call="mail.LinkPreview.aside">
                <t t-set="className" t-value="'btn btn-sm btn-dark mt-2 me-2 rounded opacity-75 opacity-100-hover'"/>
            </t>
        </div>
    </t>

    `);
    registerTemplate("mail.LinkPreviewVideo", `/mail/static/src/core/common/link_preview.xml`, `<t t-name="mail.LinkPreviewVideo" xml:space="preserve">
        <div class="o-mail-LinkPreviewVideo card position-relative w-100 mb-2 rounded bg-view shadow-sm overflow-hidden" t-att-data-provider="linkPreview.videoProvider" t-att-class="{ 'me-2': env.inChatter, 'o-mail-LinkPreviewVideo-embed': linkPreview.videoURL, 'o-mail-LinkPreviewVideo-started': state.startVideo }" t-attf-class="{{ className }}">
            <div class="row g-0 flex-row-reverse">
                <div class="col min-w-0" t-att-class="{ 'd-flex align-items-center': !linkPreview.og_description }">
                    <div class="d-flex flex-column gap-1 px-3 py-2 bg-view">
                        <p t-if="linkPreview.og_site_name" class="mb-0 card-text text-muted smaller overflow-hidden" t-out="linkPreview.og_site_name"/>
                        <h6 class="o-mail-LinkPreviewVideo-title card-title mb-0 me-2" t-attf-class="{{ linkPreview.og_description ? 'text-truncate' : 'o-mail-LinkPreviewVideo-hasDescription overflow-hidden' }}">
                            <a t-att-href="linkPreview.source_url" target="_blank" t-esc="linkPreview.og_title"/>
                        </h6>
                        <p t-if="linkPreview.og_description" class="o-mail-LinkPreviewVideo-description o-mail-LinkPreviewVideo-hasDescription card-text mb-0 text-muted small overflow-hidden" t-out="linkPreview.og_description"/>
                    </div>
                </div>
                <div t-if="!linkPreview.videoURL" class="col-4 d-block">
                    <a t-att-href="linkPreview.source_url" target="_blank"><t t-call="mail.LinkPreviewVideo.preview"/></a>
                </div>
            </div>
            <div t-if="linkPreview.videoURL" class="o-mail-LinkPreviewVideo-container">
                <div t-if="!state.videoLoaded" class="o-mail-LinkPreviewVideo-videoWrap h-100 w-100" t-on-click="() =&gt; state.startVideo = true"><t t-call="mail.LinkPreviewVideo.preview"/></div>
                <iframe t-if="state.startVideo" t-att-src="linkPreview.videoURL" class="h-100 w-100" t-att-class="{'d-none': !state.videoLoaded}" allow="autoplay" frameborder="0" allowFullScreen="true" t-ref="video"/>
            </div>
            <t t-call="mail.LinkPreview.aside">
                <t t-set="className" t-value="'fa fa-stack p-0 opacity-75 opacity-100-hover'"/>
            </t>
        </div>
    </t>

    `);
    registerTemplate("mail.LinkPreview.aside", `/mail/static/src/core/common/link_preview.xml`, `<t t-name="mail.LinkPreview.aside" xml:space="preserve">
        <div t-if="props.messageLinkPreview.message_id?.allowsEdition and !env.inLinkPreviewConfirmDelete" class="position-absolute top-0 end-0 small">
            <button t-attf-class="{{ className }}" class="o-mail-LinkPreview-aside btn" aria-label="Remove" t-on-click="onClick">
                <i class="fa fa-times"/>
            </button>
        </div>
    </t>

    `);
    registerTemplate("mail.LinkPreviewVideo.preview", `/mail/static/src/core/common/link_preview.xml`, `<t t-name="mail.LinkPreviewVideo.preview" xml:space="preserve">
        <div class="o-mail-LinkPreviewVideo-overlay position-relative h-100 rounded-bottom" t-att-class="{'bg-dark': !linkPreview.og_image}">
            <img t-if="linkPreview.og_image" class="img-fluid h-100 object-fit-cover" t-att-src="linkPreview.og_image" t-att-alt="linkPreview.og_title" t-on-load="onImageLoaded"/>
            <i t-elif="linkPreview.videoURL" class="fa fa-television fa-8x position-absolute top-50 start-50 translate-middle"/>
            <span t-else="" class="d-flex align-items-center justify-content-center w-100 h-100 bg-100 text-300">
                <i class="fa fa-camera fa-2x"/>
            </span>
            <div class="position-absolute top-50 start-50 translate-middle">
                <div t-if="!state.startVideo" class="o-mail-LinkPreviewVideo-play btn btn-lg rounded transition-base">
                    <i class="fa fa-play"/>
                </div>
                <div t-elif="!linkPreview.og_image" class="spinner-border text-muted"/>
            </div>
        </div>
    </t>
`);
    registerTemplate("mail.LinkPreviewConfirmDelete", `/mail/static/src/core/common/link_preview_confirm_delete.xml`, `<t t-name="mail.LinkPreviewConfirmDelete" xml:space="preserve">
        <Dialog size="'md'" title.translate="Confirmation" modalRef="modalRef">
            <p class="mx-3 mb-3">Do you really want to delete this preview?</p>
            <t t-component="props.LinkPreview" messageLinkPreview="props.messageLinkPreview"/>
            <t t-set-slot="footer">
                <button class="btn btn-danger me-2" t-on-click="onClickOk">Delete</button>
                <button t-if="props.messageLinkPreview.hasDeleteAll" class="btn btn-outline-danger me-2" t-on-click="onClickDeleteAll">Delete all previews</button>
                <button class="btn btn-secondary me-2" t-on-click="onClickCancel">Cancel</button>
            </t>
        </Dialog>
    </t>
`);
