    registerTemplate("mail.Thread.startMessage", `/mail/static/src/core/common/thread.xml`, `<t t-name="mail.Thread.startMessage" xml:space="preserve">
    <div class="pt-4" t-att-class="{ 'px-3': env.inChatWindow, 'px-2': env.inDiscussApp or env.inMeetingChat }">
        <div class="d-flex align-items-center gap-2" t-att-class="{             'mt-2 mb-1': !props.thread.channel?.parent_channel_id,             'mt-1': props.thread.channel?.parent_channel_id,         }">
            <div class="o-mail-Thread-avatar d-inline" t-att-class="{'o-mail-Thread-avatarChatWindow': env.inChatWindow }">
                <img t-if="!props.thread.channel?.parent_channel_id" class="rounded-3 object-fit-cover" t-att-src="props.thread?.avatarUrl" alt="Thread Image"/>
                <i t-else="" class="fa fa-comments-o text-muted" role="presentation"/>
            </div>
            <div role="heading" aria-level="1" class="text-break" t-att-class="{ 'fs-1': !env.inChatWindow, 'fs-3': env.inChatWindow }" t-esc="startMessageTitle"/>
        </div>
        <p class="text-muted mb-0 small text-break" t-esc="startMessageSubtitle"/>
    </div>
</t>
`);
    registerTemplate("mail.ThreadIcon", `/mail/static/src/core/common/thread_icon.xml`, `<t t-name="mail.ThreadIcon" xml:space="preserve">
        <div class="o-mail-ThreadIcon d-flex justify-content-center flex-shrink-0" t-att-class="props.className">
            <t t-set="sizeClass" t-value="props.size === 'large' ? 'fa-lg' : props.size === 'small' ? 'o-xsmaller' : ''"/>
            <t t-if="props.thread.channel?.channel_type === 'channel'">
                <div t-if="!props.thread.group_public_id" class="fa fa-fw fa-globe" t-att-class="sizeClass" title="Public Channel"/>
            </t>
            <t t-elif="props.thread.channel?.channel_type === 'group'">
                <t name="group"/>
            </t>
            <t t-elif="props.thread.channel?.channel_type?.includes('chat') and correspondent">
                <t name="chat">
                    <t name="chat_static">
                        <ImStatus t-if="correspondent.im_status" member="correspondent" size="props.size"/>
                        <div t-else="" class="d-flex rounded-circle bg-inherit">
                            <i class="fa-fw" t-att-class="sizeClass" t-attf-class="#{ defaultChatIcon.class }" t-att-title="defaultChatIcon.title"/>
                        </div>
                    </t>
                </t>
            </t>
            <t t-elif="props.thread.model === 'mail.box'">
                <div t-if="props.thread.id === 'inbox'" class="fa fa-fw fa-inbox" t-att-class="sizeClass"/>
                <div t-elif="props.thread.id === 'starred'" class="fa fa-fw fa-star-o" t-att-class="sizeClass"/>
                <div t-elif="props.thread.id === 'history'" class="fa fa-fw fa-history" t-att-class="sizeClass"/>
            </t>
        </div>
    </t>

`);
