    registerTemplate("discuss.CallPermissionDialog", `/mail/static/src/discuss/call/common/call_permission_dialog.xml`, `<t t-name="discuss.CallPermissionDialog" xml:space="preserve">
        <Dialog title="''" size="'md'">
            <div class="d-flex flex-fill align-items-center gap-3" t-att-class="{ 'flex-column-reverse': ui.isSmall }">
                <div>
                    <h2 t-out="permissionPrompt"/>
                    <p class="text-muted" t-out="permissionNote"/>
                </div>
                <t t-call="discuss.CallPermissionDialogImg"/>
            </div>
            <t t-set-slot="footer">
                <button class="btn btn-primary" t-on-click="props.media === 'microphone' ? onClickUseMicrophone : onClickUseCamera" t-out="primaryActionText"/>
                <button class="btn btn-secondary" t-if="rtc.cameraPermission !== 'granted' and rtc.microphonePermission !== 'granted'" t-on-click="onClickUseMicAndCamera">Use microphone and camera</button>
            </t>
        </Dialog>
    </t>

    `);
