    registerTemplate("product.ProductCatalogOrderLine", `/product/static/src/product_catalog/order_line/order_line.xml`, `<t t-name="product.ProductCatalogOrderLine" xml:space="preserve">

        <t t-portal="\`#product-\${props.productId}-price\`">
            <span t-if="showPrice" t-out="price" class="o_product_catalog_price fw-bold me-4"/>
            <span t-if="props.code" t-out="props.code" class="text-muted"/>
        </t>
        <div t-if="props.readOnly and props.warning" class="text-danger text-truncate my-2 pt-3 border-top">
            <i class="fa fa-warning" t-att-title="props.warning"/>
            <span class="px-1" t-att-title="props.warning" t-out="props.warning"/>
        </div>
        <span t-elif="props.readOnly" class="m-2 pt-3 border-top" t-out="props.warning">
            You can't edit this product in the catalog.
        </span>
        <div t-else="" class="d-flex justify-content-end align-items-center m-2">
            <div t-if="isInOrder()" class="o_product_catalog_quantity o_product_catalog_cancel_global_click input-group flex-nowrap mw-75">
                <button class="btn btn-primary border" t-on-click.stop="this.env.decreaseQuantity" t-att-disabled="disableRemove" t-att-data-tooltip="disabledButtonTooltip" aria-label="Decrease quantity">
                    <i class="oi oi-minus" aria-hidden="true"/>
                </button>
                <input class="form-control text-bg-view flex-grow-0 flex-shrink-0 text-center" name="product_catalog_quantity_input" type="number" t-att-value="quantity" t-on-change="this.env.setQuantity" t-on-focus="_onFocus"/>
                <span t-if="this.env.displayUoM" class="input-group-text d-block rounded-0 text-truncate cursor-default" t-out="props.uomDisplayName" t-att-title="props.uomDisplayName"/>
                <button class="btn btn-primary border" t-on-click.stop="(ev) =&gt; this.env.increaseQuantity()" aria-label="Increase quantity">
                    <i class="oi oi-plus" aria-hidden="true"/>
                </button>
            </div>
            <t t-elif="props.warning">
                <i class="fa fa-warning text-warning" t-att-title="props.warning"/>
                <span class="text-truncate text-warning px-1" t-att-title="props.warning" t-out="props.warning"/>
            </t>
            <div class="ms-auto o_product_catalog_buttons o_product_catalog_cancel_global_click" style="min-width: max-content;">
                <button t-if="!isInOrder()" t-on-click.stop="() =&gt; this.env.addProduct()" class="btn btn-secondary">
                    <i class="fa fa-shopping-cart"/>
                    Add
                </button>
                <div t-else="" class="o_tooltip_div_remove" t-att-data-tooltip="this.disabledButtonTooltip">
                    <button t-on-click.stop="this.env.removeProduct" t-att-disabled="disableRemove" class="btn btn-light border">
                        <i class="fa fa-trash"/>
                        Remove
                    </button>
                </div>
            </div>
        </div>
    </t>
`);
