    registerTemplate("account.AccountPaymentField", `/account/static/src/components/account_payment_field/account_payment.xml`, `<t t-name="account.AccountPaymentField" xml:space="preserve">
        <div>
            <t t-set="info" t-value="this.getInfo()"/>
            <div class="d-flex flex-column align-items-end">
                <table class="w-auto">
                    <t t-if="info.outstanding">
                        <tr>
                            <td colspan="2" class="text-start">
                                <strong id="outstanding" t-out="info.title"/>
                            </td>
                        </tr>
                    </t>
                    <t t-foreach="info.lines" t-as="line" t-key="line_index">
                        <tr>
                        <t t-if="info.outstanding">
                            <td t-out="line.formattedDate"/>
                            <td style="max-width: 9rem;">
                                <a t-att-title="(line.bank_label ? line.bank_label + ' - ' : '') + (line.move_ref ? line.move_ref : '')" role="button" class="open_account_move oe_form_field btn btn-link w-100 text-start" t-on-click="() =&gt; this.openMove(line.move_id)" data-bs-toggle="tooltip" t-att-payment-id="account_payment_id" t-out="line.journal_name"/>
                            </td>
                            <td class="ps-2">
                                <a title="assign to invoice" role="button" class="oe_form_field btn btn-secondary outstanding_credit_assign d-print-none w-100 text-start" t-att-data-id="line.id" href="#" data-bs-toggle="tooltip" t-on-click.prevent="() =&gt; this.assignOutstandingCredit(info.moveId, line.id)">Add</a>
                            </td>
                        </t>
                        <t t-if="!info.outstanding">
                            <td>
                               <a role="button" tabindex="0" class="js_payment_info fa fa-info-circle" t-att-index="line_index" style="margin-right:5px;" aria-label="Info" title="Journal Entry Info" data-bs-toggle="tooltip" t-on-click.stop="(ev) =&gt; this.onInfoClick(ev, line)"/>
                            </td>
                            <td t-if="!line.is_exchange">
                                <i class="o_field_widget text-start o_payment_label">
                                    <t t-if="line.is_refund">Reversed on </t>
                                    <t t-else="">Paid on </t>
                                    <t t-out="line.formattedDate"/>
                                </i>
                            </td>
                            <td t-if="line.is_exchange" colspan="2">
                                <i class="o_field_widget text-start text-muted text-start">
                                    <span class="oe_form_field oe_form_field_float oe_form_field_monetary fw-bold">
                                        <t t-out="line.amount_formatted"/>
                                    </span>
                                    <span> Exchange Difference</span>
                                </i>
                            </td>
                        </t>
                        <td t-if="!line.is_exchange" class="text-end ps-2 text-nowrap">
                            <span class="oe_form_field oe_form_field_float oe_form_field_monetary">
                                <t t-out="line.amount_formatted"/>
                            </span>
                        </td>
                        </tr>
                    </t>
                </table>
            </div>
        </div>
    </t>

    `);
