    registerTemplate("website.AddPageTemplatePreviews", `/website/static/src/components/dialog/add_page_dialog.xml`, `<t t-name="website.AddPageTemplatePreviews" xml:space="preserve">
    <div class="container-fluid py-3 py-xl-4">
        <div class="row g-0">
            <div t-if="this.props.isCustom and !this.props.templates.length" class="col-12 alert alert-info d-flex">
                <i class="fa fa-2x fa-info-circle me-3"/>
                To add your page to this category, open the page properties: "Site -&gt; Properties".<br/>
                Then enable the "Is a Template" option.
            </div>
            <t t-foreach="[...this.columns.entries()]" t-as="column" t-key="column[0]">
                <div class="col-lg-4 col-12">
                    <t t-foreach="[...column[1].entries()]" t-as="template" t-key="template[0]">
                        <AddPageTemplateBlank t-if="template[1].isBlank" firstRow="template_first"/>
                        <AddPageTemplatePreview t-else="" template="template[1]" firstRow="template_first" animationDelay="(column_index * 500) + (template_index * 350)" isCustom="this.props.isCustom"/>
                    </t>
                    <t t-if="column[1].length === 0">
                        <div class="o_page_template position-relative"/>
                    </t>
                </div>
            </t>
        </div>
    </div>
</t>

`);
    registerTemplate("website.AddPageTemplates", `/website/static/src/components/dialog/add_page_dialog.xml`, `<t t-name="website.AddPageTemplates" xml:space="preserve">
    <div class="overflow-hidden w-100" t-att-class="{o_loading: state.loading}">

        <div class="d-flex w-100 h-100 vertical flex-row">
            <aside class="border-end overflow-auto">
                <div t-ref="tabs" class="list-group list-group-flush flex-column flex-nowrap overflow-y-auto" role="tablist" aria-orientation="vertical" aria-label="Page categories">
                    <t t-foreach="state.pages" t-as="page" t-key="page.id">
                        <button t-att-data-id="page.id" t-on-click="() =&gt; this.onTabListBtnClick(page.id)" t-on-keydown="onTabListBtnKeydown" class="list-group-item list-group-item-action p-3" t-att-class="{active: state.activePageId === page.id}" role="tab" t-att-tabindex="state.activePageId === page.id ? 0 : -1" t-att-aria-selected="state.activePageId === page.id ? 'true' : 'false'" t-att-aria-controls="'pane_' + page.id" t-ref="{{state.activePageId === page.id ? 'autofocus' : page.id}}">
                            <span t-if="page.isPreloading" class="fa fa-spin fa-circle-o-notch me-1"/>
                            <t t-out="page.title"/>
                        </button>
                    </t>
                </div>
            </aside>
            <div t-ref="panes" class="position-relative flex-grow-1 flex-shrink-1 bg-200">
                <t t-foreach="state.pages" t-as="page" t-key="page.id">
                    <div t-att-data-id="page.id" t-att-id="'pane_' + page.id" class="o_website_page_templates_pane position-absolute top-0 start-0 w-100 h-100 overflow-y-scroll bg-200" t-att-class="{active: state.activePageId === page.id}" tabindex="-1" role="tabpanel" t-att-aria-label="page.id" t-att-inert="state.activePageId === page.id ? undefined : 'inert'">
                        <AddPageTemplatePreviews t-if="page_first or state.activePageId === page.id" templates="page.props.templates" isCustom="page.props.is_custom"/>
                    </div>
                </t>
            </div>
        </div>
    </div>
</t>

`);
