                    <i t-if="state.pageNotFound and !state.invalidUrl" class="fa fa-info-circle text-warning position-absolute top-50 end-0 translate-middle-y me-2" data-tooltip="Page not found" data-tooltip-position="top" data-tooltip-delay="0">
                    </i>
