    registerTemplate("account_accountant.AttachmentPreview", `/account_accountant/static/src/components/attachment_preview_list_view/attachment_preview_list_view.xml`, `<t t-name="account_accountant.AttachmentPreview" xml:space="preserve">
        <div t-if="previewEnabled" class="o_attachment_preview d-print-none" t-att-class="{'hidden': !attachmentPreviewState.displayAttachment}">
            <t t-if="this.attachmentPreviewState.displayAttachment">
                <t t-if="this.attachmentPreviewState.thread and this.attachmentPreviewState.thread.attachmentsInWebClientView.length &gt; 0">
                    <AccountAttachmentView threadId="this.attachmentPreviewState.thread.id" threadModel="this.attachmentPreviewState.thread.model" openInPopout="0"/>
                </t>
                <t t-elif="!this.attachmentPreviewState.selectedRecord">
                    <p class="text-center">Choose a line to preview its attachments.</p>
                </t>
                <t t-else="">
                    <p class="text-center">No attachments linked.</p>
                </t>
            </t>
            <div class="o_attachment_control toggle d-none d-md-block" t-on-click="togglePreview"/>
        </div>
        <t t-else="">
            <div class="o_popout_icon d-none d-md-block" t-on-click="() =&gt; this.setPopout(true)">
                <i class="fa fa-window-restore" title="Open attachment in pop out"/>
            </div>
            <t t-if="this.popout.active">
                <div class="o_attachment_preview d-print-none" t-if="this.attachmentPreviewState.thread?.attachmentsInWebClientView.length">
                    <AccountAttachmentView threadId="this.attachmentPreviewState.thread.id" threadModel="this.attachmentPreviewState.thread.model" openInPopout="1"/>
                </div>
            </t>
        </t>
    </t>
`);
