    registerTemplate("account_reports.AccountReportLineNameCustomizable", `/account_reports/static/src/components/account_report/line_name/line_name.xml`, `<t t-name="account_reports.AccountReportLineNameCustomizable" xml:space="preserve">
        <td data-id="line_name" class="line_name" t-att-class="lineNameClasses" t-on-click="() =&gt; this.toggleFoldable()" t-att-colspan="props.line.colspan || 1" tabindex="-1" t-ref="lineNameCell">
            <div class="wrapper">
                <t t-if="props.line.unfoldable">

                    <button data-id="btn_foldable" class="btn btn_foldable" tabindex="-1">
                        <i t-att-class="props.line.unfolded ? 'fa fa-caret-down' : 'fa fa-caret-right'"/>
                    </button>
                </t>
                <t t-else="">

                    <button class="btn btn_foldable_empty" tabindex="-1"/>
                </t>

                <t t-if="props.line.action_id">

                    <a class="clickable" t-on-click="this.triggerAction" tabindex="-1">
                        <t t-out="props.line.name"/>
                    </a>
                </t>
                <t t-elif="controller.isLoadMoreLine(props.lineIndex)">

                    <a class="clickable" t-on-click="this.loadMore" tabindex="-1">
                        <t t-out="props.line.name"/>
                    </a>
                </t>
                <t t-else="">
                    <div data-id="content" class="content">
                        <t t-component="env.component('AccountReportEllipsis')" t-props="{                             name: props.line.name?.toString(),                             type: 'string',                             maxCharacters: 80,                         }"/>

                        <AccountReviewStateSelectionBadge t-if="this.accountStatus.record" options="this.accountStatusBadgeOptions" record="this.accountStatus.record" readonly="false" name="'status'" class="'ms-2'" size="'small'"/>

                        <t t-if="hasCaretOptions">

                            <Dropdown position="'right-start'">
                                <button class="btn btn_dropdown" tabindex="-1">
                                    <i class="oi oi-ellipsis-v"/>
                                </button>
                                <t t-set-slot="content">
                                    <div data-id="caret_options">
                                        <t t-foreach="caretOptions" t-as="caretOption" t-key="caretOption_index">
                                            <DropdownItem onSelected="() =&gt; this.caretAction(caretOption)">
                                                <t t-out="caretOption.name"/>
                                            </DropdownItem>
                                        </t>
                                    </div>
                                </t>
                            </Dropdown>
                        </t>

                        <button tabindex="-1" class="btn btn_annotation" t-on-click="openChatter" t-if="this.props.line.chatter and !this.ui.isSmall" t-att-class="{                                 'o_account_report_chatter_selected': isChatterSelected,                                 'o_account_report_chatter_annoted': isChatterAnnotated,                             }">
                            <i class="fa fa-commenting" t-if="isChatterSelected || isChatterAnnotated"/>
                            <i class="fa fa-commenting-o" t-else=""/>
                        </button>

                        <t data-id="line_buttons" t-if="!props.line['hide_line_buttons']"/>
                    </div>
                </t>
            </div>
        </td>
    </t>
`);
