    registerTemplate("timesheet_grid.TimesheetTimer", `/timesheet_grid/static/src/components/static_timesheet_form/static_timesheet_timer.xml`, `<t t-name="timesheet_grid.TimesheetTimer" xml:space="preserve">
        <Record fields="timerService.timesheetTimerFields" activeFields="activeFields" resModel="model" resId="props.data?.id" mode="'edit'" t-slot-scope="data" values="props.data" context="props.context" hooks="recordHooks">
            <div class="o_group row align-items-start">
                <div class="o_inner_group d-grid">
                    <div class="o_cell o_wrap_label text-break text-900">
                        <label class="o_form_label">
                            Description
                        </label>
                    </div>
                    <div class="o_cell o_wrap_input">
                        <Field name="'name'" fieldInfo="activeFields.name" record="data.record" class="'field-description'"/>
                    </div>
                </div>
                <div class="o_inner_group d-grid col-xxl-6">
                    <div class="o_cell o_wrap_label text-break text-900">
                        <label class="o_form_label">
                            Project Name
                        </label>
                    </div>
                    <div class="o_cell o_wrap_input">
                        <Field name="'project_id'" fieldInfo="activeFields.project_id" record="data.record" class="pe-2"/>
                    </div>
                    <div class="o_cell o_wrap_label text-break text-900" name="task_label">
                        <label class="o_form_label">
                            Task Name
                        </label>
                    </div>
                    <div class="o_cell o_wrap_input" name="task_field">
                        <Field name="'task_id'" fieldInfo="activeFields.task_id" record="data.record"/>
                    </div>
                </div>
                <div class="o_inner_group d-grid col-xxl-6 ps-xxl-0">
                    <div class="o_cell o_wrap_label text-break text-900">
                        <label class="o_form_label">
                            Time Spent
                        </label>
                    </div>
                    <div class="o_cell o_wrap_input">
                        <Field name="'unit_amount'" fieldInfo="activeFields.unit_amount" record="data.record"/>
                    </div>
                </div>
            </div>

            <div class="mt-2">
                <button type="button" class="btn btn-primary" t-on-click="() =&gt; this.onSave(data.record)">
                    <t t-if="saveButtonText" t-esc="saveButtonText"/>
                    <t t-else="">Save</t>
                </button>
                <button type="button" class="btn btn-secondary ms-2" t-on-click="() =&gt; this.props.onDiscard(data.record)">
                    Discard
                </button>
                <button t-if="data.record.resId" type="button" class="btn btn-danger float-end" t-on-click="() =&gt; this.props.onDelete(data.record.resId)">
                    <i class="fa fa-times"/>
                    Delete
                </button>
            </div>
        </Record>
    </t>

`);
