    registerTemplate("web_studio.ViewEditor.GanttEditorSidebar", `/web_studio/static/src/client_action/view_editor/editors/gantt/gantt_editor_sidebar.xml`, `<t t-name="web_studio.ViewEditor.GanttEditorSidebar" xml:space="preserve">
        <InteractiveEditorSidebar>
            <t t-set-slot="view">
                <Property name="'create'" value="modelParams.canCreate === true" type="'boolean'" onChange.bind="onViewAttributeChanged">
                    Can Create
                </Property>
                <Property name="'edit'" value="modelParams.canEdit === true" type="'boolean'" onChange.bind="onViewAttributeChanged">
                    Can Edit
                </Property>
                <Property name="'display_unavailability'" value="modelParams.displayUnavailability === true" type="'boolean'" onChange.bind="onViewAttributeChanged">
                    Display Unavailability
                </Property>
                <Property name="'total_row'" value="modelParams.displayTotalRow === true" type="'boolean'" onChange.bind="onViewAttributeChanged">
                    Display Total row
                </Property>
                <Property name="'date_start'" type="'selection'" value="modelParams.dateStartField" childProps="{ choices: fieldsDateChoices }" onChange.bind="onViewAttributeChanged">
                    Start Date Field
                </Property>
                <Property name="'date_stop'" type="'selection'" value="modelParams.dateStopField" childProps="{ choices: fieldsDateChoices }" onChange.bind="onViewAttributeChanged">
                    Stop Date Field
                </Property>
                <Property name="'string'" type="'string'" value="modelParams.string" onChange.bind="onViewAttributeChanged">
                    Label
                </Property>
                <Property name="'default_group_by'" type="'selection'" value="viewEditorModel.studioViewProps.defaultGroupBy" childProps="{ choices: fieldsChoices, multiSelect: true }" onChange.bind="onDefaultGroupByChanged">
                    Default Group by
                </Property>
                <Property name="'display_mode'" type="'selection'" value="modelParams.displayMode" childProps="{ choices: displayModeChoices }" onChange.bind="onViewAttributeChanged">
                    Display Mode
                </Property>
                <Property name="'default_range'" type="'selection'" value="modelParams.defaultRange" childProps="{ choices: defaultRangesChoices }" onChange.bind="onViewAttributeChanged">
                    Default Scale
                </Property>
                <Property name="'color'" type="'selection'" value="modelParams.colorField" childProps="{ choices: colorChoices }" onChange.bind="onViewAttributeChanged">
                    Color
                </Property>
                <Property name="'precision_day'" type="'selection'" value="currentDayPrecision" childProps="{ choices: dayPrecisionChoices }" onChange.bind="(value) =&gt; this.onPrecisionChanged(value, 'day')">
                    Day Precision
                </Property>
                <Property name="'precision_week'" type="'selection'" value="currentWeekPrecision" childProps="{ choices: weekAndMonthPrecisionChoices }" onChange.bind="(value) =&gt; this.onPrecisionChanged(value, 'week')">
                    Week Precision
                </Property>
                <Property name="'precision_month'" type="'selection'" value="currentMonthPrecision" childProps="{ choices: weekAndMonthPrecisionChoices }" onChange.bind="(value) =&gt; this.onPrecisionChanged(value, 'month')">
                    Month Precision
                </Property>

                <SidebarViewToolbox onMore="props.openViewInForm" canEditXml="!viewEditorModel.isEditingSubview" openDefaultValues="props.openDefaultValues"/>
            </t>
        </InteractiveEditorSidebar>
    </t>

`);
    registerTemplate("web_studio.ViewEditor.GraphEditorSidebar", `/web_studio/static/src/client_action/view_editor/editors/graph/graph_editor_sidebar.xml`, `<t t-name="web_studio.ViewEditor.GraphEditorSidebar" xml:space="preserve">
        <InteractiveEditorSidebar>
            <t t-set-slot="view">
                <Property name="'type'" type="'selection'" value="modelParams.mode" childProps="{ choices: this.typeChoices }" onChange.bind="onViewAttributeChanged">
                    Type
                </Property>

                <Property t-if="modelParams.mode !== 'pie'" name="'order'" type="'selection'" value="modelParams.order" childProps="{ choices: this.orderChoices, required: false }" onChange.bind="onViewAttributeChanged">
                    Sorting
                </Property>


                <Property t-if="modelParams.mode !== 'line'" name="'disable_linking'" type="'boolean'" value="!modelParams.disableLinking" onChange.bind="(value, name) =&gt; this.onViewAttributeChanged(!value, name)">
                    Access records from graph
                </Property>

                <Property t-if="modelParams.mode === 'bar'" name="'stacked'" type="'boolean'" value="modelParams.stacked" onChange.bind="this.onViewAttributeChanged">
                    Stacked graph
                </Property>

                <Property name="'first_groupby'" type="'selection'" value="modelParams.groupBy[0]" childProps="{ choices: this.firstGroupbyChoices, required: false }" onChange="(value) =&gt; this.onGroupByChanged('col', value, this.oldFieldValues.firstDimension)">
                    First dimension
                </Property>

                <Property name="'second_groupby'" type="'selection'" value="modelParams.groupBy[1]" childProps="{ choices: this.secondGroupbyChoices, required: false }" onChange="(value) =&gt; this.onGroupByChanged('col', value, this.oldFieldValues.secondDimension)">
                    Second dimension
                </Property>

                <Property name="'measure'" type="'selection'" value="modelParams.measure" childProps="{ choices: this.mesureChoices, required: false }" onChange.bind="(value) =&gt; this.onGroupByChanged('measure', value, this.oldFieldValues.measure)">
                    Measure
                </Property>

                <SidebarViewToolbox onMore="props.openViewInForm" canEditXml="!viewEditorModel.isEditingSubview" openDefaultValues="props.openDefaultValues"/>
            </t>
        </InteractiveEditorSidebar>
    </t>

`);
