    registerTemplate("knowledge.KnowledgeTableOfContentPanel", `/knowledge/static/src/components/toc_panel/toc_panel.xml`, `<t t-name="knowledge.KnowledgeTableOfContentPanel" xml:space="preserve">
        <t t-if="panelState.isDisplayed('toc')">
            <div class="knowledge_toc_panel p-3">
                <t t-if="this.headings.length">
                    <h2>Table of Contents</h2>
                    <t t-foreach="this.headings" t-as="heading" t-key="heading_index">
                        <a href="#" contenteditable="false" t-out="heading.name" t-on-click.prevent="() =&gt; this.onTocLinkClick(heading)" t-attf-class="o_no_link_popover py-1 pe-1 d-block text-reset #{'o_toc_link_depth_' + heading.depth}"/>
                    </t>
                </t>
                <t t-elif="!this.tocState.tocManager?.structure.isNew">
                    <p class="o_view_nocontent_smiling_face"/>
                    <h2 class="text-center">No Title found</h2>
                    <p class="mb-0 text-center">
                        Use the /heading command to insert your first title.<br/>
                        The Table of Contents will appear here.
                    </p>
                </t>
            </div>
        </t>
    </t>
`);
