    registerTemplate("knowledge.EmbeddedViewLinkEditDialog", `/knowledge/static/src/editor/embedded_components/backend/embedded_view_link/embedded_view_link_edit_dialog.xml`, `<t t-name="knowledge.EmbeddedViewLinkEditDialog" xml:space="preserve">
        <Dialog size="'lg'" title.translate="Edit Link">
            <div class="row">
                <form role="form" class="col-lg-8">
                    <div class="d-flex">
                        <label for="inputName" class="col-form-label col-md-2">Name</label>
                        <input class="form-control" id="inputName" type="text" t-model="state.name" t-att-class="{ 'is-invalid': name === '' }" t-ref="input"/>
                    </div>
                    <div class="my-3 row">
                        <label class="col-md-2">Type</label>
                        <div class="col-md-9 d-flex gap-2 ps-1">
                            <t t-foreach="Object.entries(styles)" t-as="style" t-key="style[0]">
                                <label role="button">
                                    <span class="btn btn-sm" t-att-class="style[1].class" t-on-click="updateStyle.bind(this, style[0])">
                                        <t t-out="style[1].display"/>
                                        <i class="fa fa-check ms-1" t-if="state.style === style[0]"/>
                                    </span>
                                </label>
                            </t>
                        </div>
                    </div>
                </form>
                <div class="col-lg-4 border-start">
                    <div class="mb-3 text-center overflow-auto">
                        <label>Preview</label>
                        <div class="pt-2">
                            <a href="#" t-att-class="styles[state.style].class" t-out="state.name"/>
                        </div>
                    </div>
                </div>
            </div>
            <t t-set-slot="footer">
                <button class="btn btn-primary" t-on-click="onConfirm">
                    Save
                </button>
                <button class="btn btn-secondary" t-on-click="props.close">
                    Discard
                </button>
            </t>
        </Dialog>
    </t>
`);
