    registerTemplateExtension("calendar.AttendeeCalendarController", `/appointment/static/src/views/appointment_calendar/appointment_calendar_controller.xml`, `<t t-name="appointment.CalendarController" t-inherit="calendar.AttendeeCalendarController" t-inherit-mode="extension" xml:space="preserve">
        <xpath expr="//button[hasclass('o_calendar_button_today')]" position="before">
            <button t-if="isAppointmentManager and isResourceView" class="btn btn-primary" t-att-class="{'btn-sm btn-link p-1': env.isSmall}" t-on-click="onClickAddLeave">Add Closing Day(s)</button>
        </xpath>
        <xpath expr="//div[hasclass('o_calendar_header')]" position="inside">
            <div class="o_appointment_scheduling_box position-fixed position-md-static start-0 bottom-0 d-flex align-items-center justify-content-center gap-2 order-last order-lg-0" t-att-class="{ 'flex-lg-row flex-column' : this.appointmentState.lastAppointment.id || this.hasSlotEvents() }">
                <t t-if="env.calendarState.mode === 'slots-creation' || appointmentState.lastAppointment.url">
                    <span t-if="appointmentState.lastAppointment.url and !appointmentState.lastAppointment.waitingCopyLinkCustomType" class="text-center">
                        <i class="fa fa-check text-success" role="img" aria-label="Link copied to your clipboard!"/> Link copied to your clipboard!
                    </span>
                    <b t-else="">
                        Pick your availabilities
                    </b>
                    <div class="d-flex align-items-center gap-1 flex-wrap">
                        <button class="o_appointment_get_link btn btn-primary flex-fill text-nowrap" t-att-class="{ 'd-none': !this.appointmentState.lastAppointment.id and !this.hasSlotEvents() }" title="Get Share Link" aria-label="Get Share Link" t-on-click="onClickGetShareLink" t-ref="copyLinkRef">
                            <i class="fa fa-clipboard me-1" role="img" aria-label="Copy Link"/>Copy Link
                        </button>
                        <button class="o_appointment_open_form btn btn-secondary flex-fill text-nowrap" t-att-class="{ 'd-none': !this.appointmentState.lastAppointment.id and !this.hasSlotEvents() }" aria-label="Configure" t-on-click="onClickOpenForm">
                            <i class="fa fa-cog me-1" role="img" aria-label="Configure"/>Configure
                        </button>
                        <button class="o_appointment_discard_slots btn btn-light flex-fill" aria-label="Discard" t-on-click="onClickDiscard">
                                <i class="oi oi-close" role="img" aria-label="Discard"/>
                        </button>
                    </div>
                </t>
                <div t-else="" class="btn-group w-100 w-sm-auto mx-2 mx-sm-0 px-0">
                    <t t-set="appointments" t-value="appointmentState.data.appointment_types_info"/>
                    <div class="btn-group">
                        <Dropdown t-if="isAppointmentUser or (!isAppointmentUser and appointments.length)">
                            <button t-if="isAppointmentUser" class="btn btn-secondary dropdownAppointmentLink o-dropdown-caret">Share</button>
                            <button t-else="" class="btn btn-secondary dropdownAppointmentLink">Share Appointment Link</button>
                            <t t-set-slot="content">
                                <DropdownItem t-if="isAppointmentUser" onSelected.bind="onClickSearchCreateAnytimeAppointment" class="'o_appointment_button_link o_appointment_search_create_anytime_appointment'">
                                    My Calendar
                                </DropdownItem>
                                <DropdownItem t-if="isAppointmentUser" onSelected.bind="onClickSelectAvailabilities" class="'o_appointment_select_slots'">
                                    Specific Slots
                                </DropdownItem>
                                <DropdownItem onSelected.bind="onClickCustomLink">
                                    Custom Link
                                </DropdownItem>
                                <div t-if="appointments.length &gt; 0" role="separator" class="dropdown-divider"/>
                                <t t-foreach="appointments" t-as="appointment" t-key="appointment.id">
                                    <DropdownItem onSelected="() =&gt; this.onClickGetAppointmentUrl(appointment.id)" class="'o_appointment_button_link o_appointment_appointment_link_clipboard'">
                                        <t t-out="appointment.name"/>
                                    </DropdownItem>
                                </t>
                            </t>
                        </Dropdown>
                    </div>
                </div>
            </div>
        </xpath>
    </t>
`);
