    registerTemplate("barcode_wms.LineQuantity", `/barcode_wms/static/src/components/line.xml`, `<t t-name="barcode_wms.LineQuantity" xml:space="preserve">
        <div class="d-flex justify-content-between align-items-end">
            <div name="quantity">
                <span class="o_packaging text-muted" t-if="line.packaging_uom_id &amp;&amp; line.packaging_uom_id.id !== line.product_uom_id.id">
                    Packaging: <span t-esc="line.packaging_uom_qty"/> <span t-esc="line.packaging_uom_id.name"/>
                </span>
                <br/>
                <span t-attf-class="o_barcode_scanner_qty font-monospace fs-1">
                    <span class="qty-done" t-attf-class="                             {{nextExpected === 'quantity' &amp;&amp; qtyDone ? 'o_flash' : ''}}                             {{qtyDemand &amp;&amp; qtyDone == 0 ? env.model.zeroQtyClass(line) : ''}}                             {{qtyDemand &amp;&amp; qtyDone &amp;&amp; qtyDone == qtyDemand ? 'text-success' : ''}}" t-out="env.model.IsNotSet(line) ? '?' : qtyDone"/>
                    <span t-if="env.model.displayLineQtyDemand(line)" t-out="'/' + qtyDemand"/>
                </span>
                <small t-if="props.displayUOM" class="o_line_uom ms-1" t-out="props.line.product_uom_id.name"/>
            </div>
            <t t-if="lowerButtons !== false" t-call="{{lowerButtons || 'barcode_wms.LineLowerButtons'}}"/>
        </div>
    </t>

    `);
    registerTemplate("barcode_wms.LineLowerButtons", `/barcode_wms/static/src/components/line.xml`, `<t t-name="barcode_wms.LineLowerButtons" xml:space="preserve">
        <div t-if="displayToggleBtn">
            <button t-on-click="toggleSublines" class="o_line_button o_toggle_sublines btn btn-secondary ms-2">
                <i t-att-class="'fa fa-2x fa-angle-' + (opened ? 'up' : 'down')"/>
            </button>
        </div>
        <div t-else="" class="d-flex flex-nowrap gap-2">

            <button class="o_line_button btn px-0" style="min-width:0"/>

            <button t-if="isSelected &amp;&amp; env.model.toggleAsCounted" t-on-click="toggleAsCounted" t-attf-class="o_line_button btn btn-{{quantityIsSet ? 'warning o_unset' : 'danger o_count_zero'}}">
                <span t-if="quantityIsSet" class="fa fa-lg fa-question"/>
                <span t-else="">0</span>
            </button>
            <button t-if="isSelected &amp;&amp; qtyDone &amp;&amp; !isPackage" name="decrementButton" class="o_line_button o_remove_unit btn btn-light" t-att-disabled="!this.env.model.lineCanBeEdited(line)" t-on-click="() =&gt; this.addQuantity(-1)">
                -1
            </button>
            <button t-if="displayIncrementButton" name="incrementButton" class="o_line_button o_add_quantity btn btn-light" t-att-disabled="!this.env.model.lineCanBeEdited(line)" t-on-click="() =&gt; this.addQuantity(1)">+1</button>
            <button t-if="displayFulfillbutton" name="fulfillButton" t-on-click="() =&gt; this.addQuantity(incrementQty)" t-att-disabled="!this.env.model.lineCanBeEdited(line)" t-attf-class="o_line_button o_add_remaining_quantity btn btn-{{isSelected ? 'light' : 'secondary'}}">
                <t t-if="incrementQty &gt; 0">+</t><t t-esc="incrementQty"/>
            </button>
            <button t-if="displayDeleteButton" name="deleteButton" t-on-click="delete" t-att-disabled="!this.env.model.lineCanBeEdited(line)" class="o_line_button o_delete_line btn btn-danger">
                <span class="fa fa-lg fa-trash"/>
            </button>
            <button t-if="displayCompletePackageButton" name="completePackageButton" t-on-click="() =&gt; this.completePackage()" t-att-disabled="!this.env.model.lineCanBeEdited(line)" t-attf-class="o_line_button btn btn-{{isComplete ? 'success' : 'light'}}">
                <span class="fa f-lg fa-check"/>
            </button>
        </div>
    </t>

    `);
