    registerTemplateExtension("stock.ForecastedDetails", `/sale_stock/static/src/sale_stock_forecasted/forecasted_details.xml`, `<t t-name="sale_stock.ForecastedDetails" t-inherit="stock.ForecastedDetails" t-inherit-mode="extension" xml:space="preserve">
        <xpath expr="//tr[@name='draft_picking_out']" position="after">
            <tr t-if="currentProduct.draft_sale_qty.out" name="draft_so_out" t-attf-class="#{currentProduct.draft_sale_orders_matched and 'table-info'} #{multipleProducts and 'collapse show' or ''} collapseGroup_#{line.product.id}">
                <td/>
                <td>
                <t t-set="draft_so_out_count" t-value="currentProduct.draft_sale_orders.length"/>
                <a t-if="draft_so_out_count == 1" href="#" t-on-click.prevent="() =&gt; this.props.openView('sale.order', 'form', currentProduct.draft_sale_orders[0].id)">
                    1 Quotation</a>
                <a t-else="" href="#" t-on-click.prevent="() =&gt; this.props.openView('sale.order', 'list', false, [['id', 'in', currentProduct.draft_sale_orders.map((so) =&gt; so.id)]])">
                    <t t-out="draft_so_out_count"/> Quotations</a>
                </td>
                <td class="text-end">
                    <span class="text-danger">
                        <t t-out="_formatFloat(-currentProduct.draft_sale_qty.out)"/> <t t-out="line.uom_id.display_name"/>
                    </span>
                </td>
                <td colspan="3"/>
            </tr>
        </xpath>
        <xpath expr="//td[@name='usedby_cell']" position="inside">
            <span t-if="line.move_out and line.move_out.picking_id and line.move_out.picking_id.sale_id" t-out="' - ' + line.move_out.picking_id.sale_id.partner_id.display_name"/>
            <t t-if="line.reservation and (line.document_out._name != 'stock.picking' or line.document_out.id != line.reservation.id)">
                <span t-out="' - '"/>
                <a t-if="line.reservation" t-out="line.reservation.name" href="#" class="fw-bold" t-on-click.prevent="() =&gt; this.props.openView('stock.picking', 'form', line.reservation.id)"/>
            </t>
            <span t-if="line.document_out and line.is_matched and line.document_out._name === 'sale.order'" t-out="' (Your SO)'"/>
        </xpath>
    </t>
`);
    registerTemplate("sale_stock.QtyAtDate", `/sale_stock/static/src/widgets/qty_at_date_widget.xml`, `<t t-name="sale_stock.QtyAtDate" xml:space="preserve">
        <a t-att-tabindex="props.record.data.display_qty_widget ? '0' : '-1'" t-on-click="showPopup" t-att-class="!props.record.data.display_qty_widget ? 'invisible' : ''" t-attf-class="fa fa-area-chart cursor-pointer {{ calcData.forecasted_issue ? 'text-danger' : '' }}"/>
    </t>

    `);
    registerTemplate("sale_stock.QtyAtDatePopover", `/sale_stock/static/src/widgets/qty_at_date_widget.xml`, `<t t-name="sale_stock.QtyAtDatePopover" xml:space="preserve">
        <div class="p-2">
        <h6>Availability</h6>
        <table class="table table-borderless table-sm">
            <tbody>
                <t t-if="!props.record.data.is_mto and ['draft', 'sent'].includes(props.record.data.state)">
                    <tr>
                        <td><strong t-out="forecastedLabel"/><br/><small>On <span t-out="props.calcData.delivery_date"/></small></td>
                        <td class="text-end">
                            <b t-out="props.record.data.virtual_available_at_date"/> <t t-out="props.record.data.product_uom_id[1]"/>
                            <t t-if="props.record.data.product_uom_id[1] !== props.calcData.product_uom_name">
                                <br/><span class="fs-7 text-muted" t-out="props.calcData.product_uom_virtual_available_at_date"/> <span class="fs-7 text-muted" t-out="props.calcData.product_uom_name"/>
                            </t>
                        </td>
                    </tr>
                    <tr>
                        <td><strong t-out="availableLabel"/><br/><small>All planned operations included</small></td>
                        <td class="text-end">
                            <b t-out="props.record.data.free_qty_today" t-att-class="!props.calcData.will_be_fulfilled ? 'text-danger': ''"/> <t t-out="props.record.data.product_uom_id[1]"/>
                            <t t-if="props.record.data.product_uom_id[1] !== props.calcData.product_uom_name">
                                <br/><span t-out="props.calcData.product_uom_free_qty_today" t-att-class="\`fs-7 text-muted \${!props.calcData.will_be_fulfilled ? 'text-danger': ''}\`"/> <span class="fs-7 text-muted" t-out="props.calcData.product_uom_name"/>
                            </t>
                        </td>
                    </tr>
                </t>
                <t t-elif="props.record.data.is_mto and ['draft', 'sent'].includes(props.record.data.state)">
                    <tr>
                        <td><strong>Expected Delivery</strong></td>
                        <td class="oe-right"><span t-out="props.calcData.delivery_date"/></td>
                    </tr>
                    <tr>
                        <p>This product is replenished on demand.</p>
                    </tr>
                </t>
                <t t-elif="props.record.data.state == 'sale'">
                    <tr>
                        <td>
                            <strong>Reserved</strong><br/>
                        </td>
                        <td style="min-width: 50px; text-align: right;">
                            <b t-out="props.record.data.qty_available_today"/> <t t-out="props.record.data.product_uom_id[1]"/>
                        </td>
                    </tr>
                    <tr t-if="props.record.data.qty_available_today &lt; props.record.data.qty_to_deliver">
                        <td>
                            <span t-if="props.calcData.will_be_fulfilled and props.calcData.forecast_expected_date_str">
                                Remaining demand available at <b t-out="props.calcData.forecast_expected_date_str" t-att-class="props.record.data.scheduled_date &lt; props.record.data.forecast_expected_date ? 'text-danger' : ''"/>
                            </span>
                            <span t-elif="!props.calcData.will_be_fulfilled and props.calcData.forecast_expected_date_str" class="text-danger">
                                Not enough future availability
                            </span>
                            <span t-elif="!props.calcData.will_be_fulfilled" class="text-danger">
                                No future availability
                            </span>
                            <span t-else="">
                                Available in stock
                            </span>
                        </td>
                    </tr>
                </t>
            </tbody>
        </table>
        <button t-if="!props.record.data.is_mto" class="text-start btn btn-link" type="button" t-on-click="openForecast">
            <i class="oi oi-fw o_button_icon oi-arrow-right"/>
            View Forecast
        </button>
        </div>
    </t>
`);
    registerTemplate("sale_stock.DelayAlertWidget", `/sale_stock/static/src/xml/delay_alert.xml`, `<div t-name="sale_stock.DelayAlertWidget" class="m-1" xml:space="preserve">
        <p>The delivery
            <t t-foreach="props.late_elements" t-as="late_element" t-key="late_element.id">
                <a t-esc="late_element.name" href="#" t-on-click="openElement" t-att-element-id="late_element.id" t-att-element-model="late_element.model"/>,
            </t> will be late.
        </p>
    </div>
`);
    registerTemplateExtension("sale_stock.QtyAtDate", `/sale_stock_renting/static/src/widgets/qty_at_date_widget.xml`, `<t t-name="sale_stock_renting.QtyAtDate" t-inherit="sale_stock.QtyAtDate" t-inherit-mode="extension" xml:space="preserve">
        <xpath expr="//a" position="attributes">
            <attribute name="t-attf-class">fa fa-area-chart cursor-pointer {{ (calcData.forecasted_issue || !(props.record.data.available_reserved_lots ?? true)) ? 'text-danger' : '' }}</attribute>
        </xpath>
    </t>

    `);
    registerTemplateExtension("sale_stock.QtyAtDatePopover", `/sale_stock_renting/static/src/widgets/qty_at_date_widget.xml`, `<t t-name="sale_stock_renting.QtyAtDatePopover" t-inherit="sale_stock.QtyAtDatePopover" t-inherit-mode="extension" xml:space="preserve">
        <xpath expr="//div" position="attributes">
            <attribute name="t-if">!props.record.data.is_rental || !props.record.data.return_date || !props.record.data.start_date</attribute>
        </xpath>
        <xpath expr="//div" position="after">
            <div class="p-2" t-else="">
            <h6>Availability</h6>
            <table class="table table-borderless table-sm">
                <tbody>
                    <tr>
                        <td>
                            <strong>Available for Rent</strong><br/>
                            <small> <span t-out="props.calcData.stock_start_date"/></small>
                            <small> to <span t-out="props.calcData.stock_end_date"/></small>
                        </td>
                        <td class="text-end">
                            <t t-out="props.record.data.virtual_available_at_date"/> <t t-out="props.record.data.product_uom_id[1]"/>
                        </td>
                    </tr>
                </tbody>
            </table>
            <t t-if="!(props.record.data.available_reserved_lots ?? true)">
                <strong class="text-danger">Reserved lots unavailable</strong><br/>
            </t>
            <button class="text-start btn btn-link" type="button" t-on-click="openRentalGanttView">
                <i class="oi oi-fw o_button_icon oi-arrow-right"/>
                View Rentals
            </button>
            </div>
        </xpath>
    </t>
`);
    registerTemplate("account_asset.moveReversed", `/account_asset/static/src/components/move_reversed/move_reversed.xml`, `<t t-name="account_asset.moveReversed" xml:space="preserve">
        <i t-if="props.record.data[props.name].records.length" class="fa fa-exclamation-circle" title="This move has been reversed"/>
    </t>
`);
    registerTemplate("ImportAction", `/base_import/static/src/import_action/import_action.xml`, `<t t-name="ImportAction" xml:space="preserve">
        <div t-ref="root" class="h-100 d-flex flex-column">
            <Layout className="'o_import_action d-flex h-100 overflow-auto'" display="display">
                <t t-set-slot="control-panel-buttons">
                    <t t-if="isPreviewing">
                        <t t-if="!state.isTested">
                            <button type="button" class="btn btn-primary" t-on-click="() =&gt; this.handleImport(true)">Test</button>
                            <button t-if="!state.isPaused" type="button" class="btn btn-secondary" t-on-click="() =&gt; this.handleImport(false)">Import</button>
                            <button t-else="" type="button" class="btn btn-secondary" t-on-click="() =&gt; this.handleImport(false)">Resume</button>
                        </t>
                        <t t-else="">
                            <button t-if="!state.isPaused" type="button" class="btn btn-primary" t-on-click="() =&gt; this.handleImport(false)">Import</button>
                            <button t-else="" type="button" class="btn btn-primary" t-on-click="() =&gt; this.handleImport(false)">Resume</button>
                            <button type="button" class="btn btn-secondary" t-on-click="() =&gt; this.handleImport(true)">Test</button>
                        </t>
                    </t>
                    <FileInput acceptedFileExtensions="'.csv, .xls, .xlsx, .xlsm, .ods'" onUpload.bind="(data, files) =&gt; this.handleFilesUpload(files)" resId="model.id" resModel="this.resModel" route="this.uploadFilesRoute">
                        <button t-if="isPreviewing" type="button" class="btn btn-secondary">Load Data File</button>
                        <button t-else="" type="button" class="btn btn-primary o_import_file">Upload Data File</button>
                    </FileInput>
                    <button t-on-click="cancel" type="button" class="btn btn-secondary">Cancel</button>
                </t>
                <t t-if="isPreviewing">
                    <ImportDataSidepanel filename="state.filename" options="importOptions" formattingOptions="formattingOptions" importTemplates="importTemplates" isBatched="isBatched" onOptionChanged.bind="onOptionChanged" onReload.bind="reload" hasBinaryFields="hasBinaryFields" binaryFilesParams="model.binaryFilesParams" onBinaryFilesParamsChanged.bind="(name, value) =&gt; model.onBinaryFilesParamsChanged(name, value)"/>
                    <ImportDataContent columns="model.columns" onFieldChanged.bind="onFieldChanged" onOptionChanged.bind="onOptionChanged" options="importOptions" isFieldSet.bind="isFieldSet" previewError="state.previewError" importMessages="model.importMessages"/>
                </t>
                <div t-else="" class="o_view_nocontent">
                    <div class="o_nocontent_help">
                        <p class="o_view_nocontent_smiling_face">
                            Drop or upload a file to import
                        </p>
                        <p>
                            Excel files are recommended as formatting is automatic.<br/>
                            But, you can also use .csv files
                        </p>
                        <div class="mt16 mb4">
                            Need Help? <DocumentationLink path="'/applications/general/export_import_data.html'" label.translate="Import FAQ"/>
                        </div>
                        <div t-foreach="importTemplates" t-as="template" t-key="template.template">
                            <a class="btn btn-outline-primary my8" t-att-href="template.template" aria-label="Download" data-tooltip="Download">
                                <i class="fa fa-download"/> <span><t t-esc="template.label"/></span>
                            </a>
                        </div>
                    </div>
                </div>
            </Layout>
        </div>
    </t>
`);
    registerTemplate("base_import.BlockUI", `/base_import/static/src/import_block_ui.xml`, `<t t-name="base_import.BlockUI" xml:space="preserve">
        <div class="o_blockUI fixed-top d-flex justify-content-center align-items-center flex-column vh-100 bg-black-50">
            <div class="o_spinner mb-4">
                <img src="/web/static/img/spin.svg" alt="Loading..."/>
            </div>
            <div t-if="props.message or props.blockComponent">
                <div class="o_message text-center px-4" t-esc="props.message"/>
                <t t-if="props.blockComponent" t-component="props.blockComponent.class" t-props="props.blockComponent.props"/>
            </div>
        </div>
    </t>

`);
    registerTemplate("ImportDataColumnError", `/base_import/static/src/import_data_column_error/import_data_column_error.xml`, `<t t-name="ImportDataColumnError" xml:space="preserve">
        <div class="o_import_report alert alert-danger mb-2">
            <t t-if="props.errors.length &gt; 1">
                <p>
                    <t t-if="props.errors[0].value">No matching records found for the following name </t>
                    <t t-else="">Multiple errors occurred </t>
                      in field <b t-esc="props.fieldInfo.label"/>:
                </p>
                <ul>
                    <t t-foreach="props.errors" t-as="error" t-key="error_index">
                        <a t-if="error_index === 3" href="#" class="o_import_report_count" t-on-click="() =&gt; this.state.isExpanded = !this.state.isExpanded">
                            <i t-attf-class="fa fa-chevron-{{state.isExpanded ? 'up' : 'down'}}"/> <t t-esc="props.errors.length - error_index"/> more
                        </a>
                        <li t-if="isErrorVisible(error_index)" t-attf-class="o_import_report_more p-0 text-{{error.priority}} {{error_index &gt; 2 ? 'list-unstyled' : ''}}">
                            <t t-if="error.rows.from === error.rows.to">
                                <b t-esc="error.value"/> at row <t t-esc="error.rows.from + 1"/>
                                <t t-if="props.resultNames and props.resultNames.length &gt; error.rows.from and props.resultNames[error.rows.from] !== ''">
                                    (<t t-esc="props.resultNames[error.rows.from]"/>)
                                </t>
                            </t>
                            <t t-else=""><b t-esc="error.value || error.message"/> at multiple rows</t>
                        </li>
                    </t>
                </ul>
            </t>
            <p t-else="" t-attf-class="mb-0 p-2 alert-{{props.errors[0].type}}" t-esc="props.errors[0].message"/>
            <t t-if="moreInfo">
                <t t-if="typeof moreInfo === 'string'" t-esc="moreInfo"/>
                <div t-else="" class="o_import_moreinfo" t-on-click="onMoreInfoClicked">
                    <a href="#" class="o_import_see_all">
                        <i class="oi oi-arrow-right"/> See possible values
                    </a>
                </div>
                <ul t-if="state.moreInfoContent" class="o_import_report_more">
                    <li t-foreach="state.moreInfoContent" t-as="msg" t-key="msg_index"><t t-esc="msg"/></li>
                </ul>
            </t>
        </div>
    </t>
`);
    registerTemplate("ImportDataContent", `/base_import/static/src/import_data_content/import_data_content.xml`, `<t t-name="ImportDataContent" xml:space="preserve">
        <div class="o_import_data_content flex-grow-1 overflow-auto border-start">
            <div t-if="props.previewError" class="border-bottom p-2">
                <div class="alert alert-danger mb-0">
                    <p>
                        Import preview failed due to: "
                        <t t-esc="props.previewError"/>
                        ".
                    </p>
                    <p>For CSV files, you may need to select the correct separator.</p>
                    <p t-if="props.columns.length &gt; 0">Here is the start of the file we could not import:</p>
                </div>
            </div>
            <div t-if="!props.options.has_headers" class="border-bottom p-2">
                <p class="alert alert-info mb-0">
                    If the file contains
                    the column names, Odoo can try auto-detecting the
                    field corresponding to the column. This makes imports
                    simpler especially when the file has many columns.
                </p>
            </div>
            <div t-if="props.importMessages.length &gt; 0" class="border-bottom p-2">
                <t t-foreach="props.importMessages" t-as="message" t-key="\`\${message.lines[0]}-\${message_index}\`">
                    <p t-att-class="getErrorMessageClass(props.importMessages, message.type, message_index)">
                        <t t-foreach="message.lines" t-as="line" t-key="\`\${line}-\${line_index}\`">
                            <b t-esc="line"/><br/>
                        </t>
                    </p>
                </t>
            </div>
            <table t-if="!props.previewError" class="table table-borderless w-100 bg-view">
                <thead>
                    <tr class="border-bottom">
                        <th scope="col">File Column</th>
                        <th scope="col">Odoo Field</th>
                        <th scope="col">Comments</th>
                    </tr>
                </thead>
                <tbody>
                    <t t-foreach="props.columns" t-as="column" t-key="\`\${column_index}-\${column.id}\`">
                        <tr class="border-bottom align-middle">
                            <td>
                                <div class="o_import_file_column_cell d-flex flex-column user-select-none">
                                    <span class="fw-bold text-truncate">
                                        <span class="text-truncate" t-if="column.name" t-esc="column.name"/>
                                        <span t-else="">Untitled</span>
                                    </span>
                                    <span t-if="props.options.has_headers" class="o_import_preview fst-italic small pe-2" data-tooltip-template="ImportDataContent.tooltip" t-att-data-tooltip-info="getTooltip(column)" data-tooltip-position="right">
                                        <t t-esc="column.preview"/>
                                    </span>
                                </div>
                            </td>
                            <td>
                                <SelectMenu value="column.fieldInfo ? column.fieldInfo.fieldPath : undefined" groups="getGroups(column)" onSelect="(fieldPath) =&gt; this.onFieldChanged(column, fieldPath)" searchPlaceholder.translate="Search a field...">
                                    <t t-if="column.fieldInfo">
                                        <i class="o_import_field_icon border-end" t-att-class="'position-absolute d-inline-block o_import_field_icon_' + column.fieldInfo.type" data-tooltip-template="web.FieldTooltip" t-att-data-tooltip-info="getTooltipDetails(column.fieldInfo)"/>
                                        <span class="ps-5">
                                            <t t-esc="column.fieldInfo.label"/>
                                        </span>
                                    </t>
                                    <span t-else="" class="text-warning">To import, select a field...</span>

                                    <t t-set-slot="choice" t-slot-scope="choice">
                                        <div t-att-class="\`\${choice.data.value and choice.data.value.required ? 'fw-bolder text-decoration-underline' : ''}\`">
                                            <i class="o_import_field_choice o_import_field_icon position-relative d-inline-block align-middle border-end me-2" t-att-class="choice.data.iconClass"/>
                                            <t t-esc="choice.data.label"/>
                                        </div>
                                    </t>
                                </SelectMenu>
                            </td>
                            <td>
                                <t t-foreach="column.comments" t-as="comment" t-key="comment_index">
                                    <p class="m-0 p-2 alert" t-att-class="getCommentClass(column, comment, comment_index)"><t t-out="comment.content"/> <b t-if="comment.fieldName" t-out="comment.fieldName"/></p>
                                </t>
                                <ImportDataColumnError t-if="column.errors.length" errors="column.errors" resultNames="column.resultNames" fieldInfo="column.fieldInfo"/>
                                <ImportDataOptions t-if="column.errors.length or column.importOptions" importOptions="column.importOptions" fieldInfo="column.fieldInfo" onOptionChanged="props.onOptionChanged"/>
                            </td>
                        </tr>
                    </t>
                </tbody>
            </table>
        </div>
    </t>

    `);
    registerTemplate("ImportDataContent.tooltip", `/base_import/static/src/import_data_content/import_data_content.xml`, `<t t-name="ImportDataContent.tooltip" xml:space="preserve">
        <h5 class="text-reset p-2 m-0">Preview</h5>
        <hr class="m-0"/>
        <div class="p-2 pe-3">
            <p t-foreach="lines" t-as="line" t-key="line_index" t-out="line" class="mb-0 fs-6"/>
        </div>
    </t>
`);
    registerTemplate("ImportDataOptions", `/base_import/static/src/import_data_options/import_data_options.xml`, `<t t-name="ImportDataOptions" xml:space="preserve">
        <div t-if="isVisible and state.options.length &gt; 1" t-attf-class="o_import_dropdown o_import_field_#{props.fieldInfo.type} alert alert-danger mb-2">
            <b>When a value cannot be matched:</b>
            <select class="o_import_create_option form-select w-auto bg-light" t-att-type="props.fieldInfo.type" t-on-change="onSelectionChanged">
                <option t-foreach="state.options" t-as="option" t-key="option" t-att-value="option[0]">
                    <t t-esc="option[1]"/>
                </option>
            </select>
        </div>
    </t>
`);
    registerTemplate("ImportDataProgress", `/base_import/static/src/import_data_progress/import_data_progress.xml`, `<t t-name="ImportDataProgress" xml:space="preserve">
        <div t-if="props.importProgress.step &gt; 1" class="o_import_data_progress d-flex align-items-center flex-column">
            <div class="o_import_progress_dialog_batch text-center">
                Batch <span class="o_import_progress_dialog_batch_count"><t t-esc="props.importProgress.step"/></span> out of <span t-esc="props.totalSteps"/>...
                <div t-if="props.importProgress.value and state.timeLeft and !state.isInterrupted" class="o_import_progress_dialog_time_left">
                    <span>Estimated time left:</span>
                    <t t-if="state.timeLeft &gt;= 1">
                        <span class="o_import_progress_dialog_time_left_text mx-1" t-esc="minutesLeft"/><span>minutes</span>
                    </t>
                    <t t-else="">
                        <span class="o_import_progress_dialog_time_left_text mx-1" t-esc="secondsLeft"/><span>seconds</span>
                    </t>
                </div>
            </div>
            <span t-if="state.isInterrupted" class="o_import_progress_dialog_stop">
                Finalizing current batch before interrupting...
            </span>
            <div t-else="" class="d-flex align-items-center mt-2">
                <div class="progress flex-grow-1 rounded-3">
                    <div class="progress-bar progress-bar-striped" role="progressbar" aria-valuenow="props.importProgress" aria-valuemin="0" aria-valuemax="100" aria-label="Progress bar" t-att-style="'width: ' + props.importProgress.value + '%'">
                        <span class="fs-4"><t t-esc="props.importProgress.value"/>%</span>
                    </div>
                </div>
                <a class="o_progress_stop_import ms-2" role="button" t-on-click="interrupt"><i class="fa fa-close fs-2 text-danger" aria-label="Stop Import" title="Stop Import"/></a>
            </div>
        </div>
    </t>
`);
    registerTemplate("ImportDataSidepanel", `/base_import/static/src/import_data_sidepanel/import_data_sidepanel.xml`, `<t t-name="ImportDataSidepanel" xml:space="preserve">
        <div class="o_import_data_sidepanel p-3 bg-view">
            <div class="pb-4">
                <h4>Data to import</h4>
                <div class="mb-2 d-flex align-items-center">
                    <i class="fa fa-file white me-2"/>
                    <div class="fst-italic truncate"><t t-esc="fileName"/></div>
                    <span class="fst-italic"><t t-esc="fileExtension"/></span>
                </div>

                <div t-if="props.options.sheets.length &gt; 0" class="flex-row my-2">
                    <label for="o_import_sheet">Sheet:</label>
                    <select class="o_select o_import_sheet w-100 mb-3 form-select" name="o_import_sheet" t-on-change="ev =&gt; this.props.onOptionChanged('sheet', ev.target.value)" t-att-value="props.options.sheet">
                        <option t-foreach="props.options.sheets" t-as="sheet" t-key="sheet" t-att-value="sheet" t-att-selected="sheet === props.options.sheet">
                            <t t-esc="sheet"/>
                        </option>
                    </select>
                </div>
                <CheckBox value="props.options.has_headers" onChange.bind="isChecked =&gt; this.props.onOptionChanged('has_headers', isChecked)">
                    Use first row as header
                </CheckBox>
            </div>
            <div t-if="fileExtension.toLowerCase() === '.csv'" class="o_import_formatting pt-3 pb-4 border-top">
                <h4>Formatting</h4>
                <div t-foreach="Object.entries(props.formattingOptions)" t-as="option" t-key="\`\${option[0]}-\${option_index}\`" class="o_import_options">
                    <label t-att-for="\`\${option[0]}-\${option_index}\`">
                        <t t-esc="option[1].label"/>
                        <sup t-if="option[1].help" class="text-info p-1" t-att-data-tooltip="option[1].help" t-esc="'?'"/>
                    </label>
                    <input t-if="option[1].type === 'input'" t-att-id="\`\${option[0]}-\${option_index}\`" t-att-list="option[1].options ? \`list-\${ option_index }\` : null" t-attf-class="o_import_#{option[0]} o_import_dropdown w-100 mb-3" t-att-value="option[1].value" t-on-change="(ev) =&gt; this.setOptionValue(option[0], ev.target.value)"/>
                    <datalist t-if="option[1].type === 'input' and option[1].options" t-att-id="\`list-\${ option_index }\`">
                        <option t-foreach="option[1].options" t-as="opt" t-key="opt_index" t-att-value="opt.value or opt" t-att-selected="opt.value ? opt.value === option[1].value : opt === option[1].value">
                            <t t-esc="opt.label ? opt.label : opt"/>
                        </option>
                    </datalist>
                    <select t-elif="option[1].type === 'select'" t-att-class="\`o_select form-select w-100 mb-3 o_import_\${option[0]} o_import_dropdown\`" t-att-name="\`\${option[0]}-\${option_index}\`" t-on-change="(ev) =&gt; this.setOptionValue(option[0], ev.target.value)">
                        <option t-foreach="option[1].options" t-as="opt" t-key="opt_index" t-att-value="opt.value or opt.value === '' ? opt.value : opt" t-att-selected="opt.value or opt.value === '' ? opt.value === option[1].value : opt === option[1].value">
                            <t t-esc="opt.label ? opt.label : opt"/>
                        </option>
                    </select>
                </div>
                <button class="btn btn-primary w-100" t-on-click="() =&gt; this.props.onReload()">Reimport</button>
            </div>
            <div t-if="props.isBatched" class="pt-3 pb-4 border-top">
                <h4>Batch Import</h4>
                <div class="o_import_batch_alert fw-bold pb-2">
                    The file will be imported by batches
                </div>
                <div class="d-flex">
                    <div class="o_import_batch_limit w-50 pe-1">
                        <label class="mb-1" for="o_import_batch_limit">Batch limit</label>
                        <input class="w-100" id="o_import_batch_limit" t-att-value="getOptionValue('limit')" t-on-change="(ev) =&gt; this.setOptionValue('limit', ev.target.value || 1)"/>
                    </div>
                    <div class="w-50 ps-1" data-tooltip="Warning: ignores the labels line, empty lines and lines composed only of empty cells">
                        <label class="mb-1" for="o_import_row_start">Start at line</label>
                        <input class="w-100" id="o_import_row_start" t-att-value="getOptionValue('skip')" t-on-change="onLimitChange"/>
                    </div>
                </div>
            </div>
            <div t-if="props.hasBinaryFields" class="pt-3 pb-4 border-top o_import_file">
                <h4>Files to import</h4>
                <div class="o_import_grid gap-1">

                    <div class="o_import_grid_col">
                        <label>
                            <span class="btn btn-sm btn-primary">Upload your files</span>
                            <input type="file" multiple="multiple" hidden="hidden" t-on-change="(event) =&gt; this.props.onBinaryFilesParamsChanged('binaryFiles', event.target.files)"/>
                        </label>
                    </div>
                    <div class="o_import_grid_col o_grid_span_2">
                        <t t-esc="binaryFilesLabel"/>
                    </div>


                    <t t-if="env.debug">
                        <div class="o_import_grid_col">
                            <label for="o_input_maxSizePerBatch">Max size per batch</label>
                            <sup t-if="props.binaryFilesParams.maxSizePerBatch.help" class="text-info p-1 cursor-default" t-att-data-tooltip="props.binaryFilesParams.maxSizePerBatch.help" t-esc="'?'"/>
                        </div>
                        <div class="o_import_grid_col">
                                <input type="number" id="o_input_maxSizePerBatch" t-att-value="props.binaryFilesParams.maxSizePerBatch.value" t-att-max="props.binaryFilesParams.maxSizePerBatch.max" t-att-min="props.binaryFilesParams.maxSizePerBatch.min" t-on-change="(event) =&gt; this.props.onBinaryFilesParamsChanged('maxSizePerBatch', event.target.value)"/>
                        </div>
                        <div class="o_import_grid_col">
                            <label for="o_input_maxSizePerBatch">Mb</label>
                        </div>


                        <div class="o_import_grid_col">
                            <label for="o_input_delayAfterEachBatch">Delay after each batch</label>
                            <sup t-if="props.binaryFilesParams.delayAfterEachBatch.help" class="text-info p-1 cursor-default" t-att-data-tooltip="props.binaryFilesParams.delayAfterEachBatch.help" t-esc="'?'"/>
                        </div>
                        <div class="o_import_grid_col">
                                <input type="number" id="o_input_delayAfterEachBatch" t-att-value="props.binaryFilesParams.delayAfterEachBatch.value" t-att-min="props.binaryFilesParams.delayAfterEachBatch.min" t-on-change="(event) =&gt; this.props.onBinaryFilesParamsChanged('delayAfterEachBatch', event.target.value)"/>
                        </div>
                        <div class="o_import_grid_col">
                            <label for="o_input_delayAfterEachBatch">seconds</label>
                        </div>
                    </t>
                </div>

            </div>
            <div t-if="env.debug" class="o_import_debug_options pt-3 pb-4 border-top">
                <h4>Advanced</h4>
                <div data-tooltip="If the model uses openchatter, history tracking will set up subscriptions and send notifications during the import, but lead to a slower import.">
                    <CheckBox value="!props.options.tracking_disable" onChange.bind="(isChecked) =&gt; this.props.onOptionChanged('tracking_disable', !isChecked)">
                        Track history during import
                    </CheckBox>
                </div>
                <CheckBox value="props.options.advanced" onChange.bind="(isChecked) =&gt; this.props.onOptionChanged('advanced', isChecked)">
                    Allow matching with subfields
                </CheckBox>
            </div>
            <div class="pt-3 pb-4 border-top">
                <h4>Help</h4>
                <t t-foreach="props.importTemplates" t-as="template" t-key="template">
                    <a class="d-block my-2" t-att-href="template.template" aria-label="Download" data-tooltip="Download">
                        <i class="fa fa-download"/> <span><t t-esc="template.label"/></span>
                    </a>
                </t>
                <DocumentationLink path="'/applications/general/export_import_data.html'" icon="'fa-external-link'" label.translate="Go to Import FAQ"/>
            </div>
        </div>
    </t>
`);
