    registerTemplate("mrp_workorder.MrpRegisterProductionDialog", `/mrp_workorder/static/src/mrp_display/dialog/mrp_register_production_dialog.xml`, `<t t-name="mrp_workorder.MrpRegisterProductionDialog" xml:space="preserve">
    <div class="o_tablet_popups o_mrp_register_production_dialog">
        <Dialog size="'md'" title="props.title" modalRef="modalRef">
            <t t-set-slot="header">
                <div class="d-flex flex w-100">
                    <div class="h4 align-self-end" t-esc="props.title"/>
                    <div t-on-click="_cancel" type="button" class="btn-close" aria-label="Close"/>
                </div>
            </t>
            <div class="o_workorder_bar_content d-grid gap-2">
                <span>Quantity Produced</span>
                <div>
                    <span name="qty_done" class="o_field_widget text-end pe-2">
                        <FloatField t-props="qtyDoneInfo" readonly="props.record.data.product_tracking === 'serial'"/>
                    </span>
                    <span>
                        /<span name="product_qty" class="mx-2" t-esc="formatFloat(quantityToProduce)"/>
                        <span t-esc="props.record.data.product_uom_id.display_name"/>
                    </span>
                </div>
                <t t-if="props.record.data.product_tracking &amp;&amp; props.record.data.product_tracking !== 'none'" class="">
                    <span class="text-capitalize" t-out="props.record.data.product_tracking"/>
                    <div class="d-flex gap-2">
                        <div t-if="props.record.data.product_tracking == 'serial' ? props.record.data.product_qty == 1 : true" name="lot_producing_ids" class="o_field_widget">
                            <Many2ManyTagsField t-props="lotInfo" readonly="props.record.data.lot_producing_ids.count &gt; 0"/>
                        </div>
                        <button t-if="props.record.data.product_tracking == 'serial' &amp;&amp; props.record.data.lot_producing_ids.count == 0" t-att-disabled="state.disabled" class="btn btn-primary btn-sm" t-on-click="actionGenerateSerial">
                            Generate Serial
                        </button>
                        <button t-if="props.record.data.product_tracking == 'lot' &amp;&amp; props.record.data.lot_producing_ids.count == 0" t-att-disabled="state.disabled" class="btn btn-primary btn-sm" t-on-click="actionGenerateSerial">
                            Generate Lot
                        </button>
                        <button t-if="props.record.data.lot_producing_ids.count" t-att-disabled="state.disabled" class="btn btn-secondary btn-sm" t-on-click="actionClearLotProducing">
                            Clear
                        </button>
                    </div>
                </t>
            </div>
            <t t-set-slot="footer">
                <button class="btn btn-primary me-2" t-on-click="validate" t-att-disabled="state.disabled">Validate</button>
            </t>
        </Dialog>
        </div>
    </t>
`);
    registerTemplate("mrp_workorder.MrpWorkcenterDialog", `/mrp_workorder/static/src/mrp_display/dialog/mrp_workcenter_dialog.xml`, `<t t-name="mrp_workorder.MrpWorkcenterDialog" xml:space="preserve">
        <Dialog size="state.noWorkcenters ? 'sm' : 'lg'" title="props.title" modalRef="modalRef">
                <div class="o_mrp_workcenter_dialog container px-0">
                    <div class="row row-cols-1 row-cols-sm-2 row-cols-md-3 row-cols-lg-4 g-2">
                        <t t-foreach="workcenters" t-as="workcenter" t-key="workcenter.id">
                            <div class="col">
                                <div class="o_workcenter_button form-check btn btn-outline-secondary d-flex align-items-center py-3 w-100 h-100 text-start" t-att-class="{'active' : active}" t-on-click.prevent="() =&gt; this.selectWorkcenter(workcenter)">
                                    <label class="form-check-label cursor-pointer" t-out="workcenter.display_name" t-att-for="'o_workcenter_checkbox_' + workcenter.id"/>
                                    <input class="form-check-input ms-auto" type="checkbox" t-att-id="'o_workcenter_checkbox_' + workcenter.id" t-att-checked="active"/>
                                </div>
                            </div>
                        </t>
                    </div>
                    <div t-if="state.noWorkcenters" class="d-flex flex-column mx-auto">
                            <button class="btn btn-primary btn-lg mb-2" t-on-click="createWorkcenter">
                                Create new work center
                            </button>
                            <button class="btn btn-secondary btn-lg" t-on-click="confirm">
                                Configure later
                            </button>
                        </div>
                    <t t-set-slot="footer" t-if="!state.noWorkcenters">
                        <button class="btn btn-primary" t-att-class="{'disabled': props.radioMode &amp;&amp; !state.activeWorkcenters.length}" t-on-click="confirm">Confirm</button>
                        <button class="btn btn-secondary" t-on-click="_cancel">Cancel</button>
                    </t>
                </div>
        </Dialog>
    </t>
`);
    registerTemplate("mrp_workorder.MrpWorksheetDialog", `/mrp_workorder/static/src/mrp_display/dialog/mrp_worksheet_dialog.xml`, `<t t-name="mrp_workorder.MrpWorksheetDialog" xml:space="preserve">
        <div class="o_tablet_popups o_worksheet_modal">
            <Dialog size="'fs'" title.translate="Worksheet" modalRef="modalRef" footer="false">
                <div class="o_tablet_instruction_note" t-out="props.worksheetText"/>
                <DocumentViewer t-if="props.worksheetData" t-props="props.worksheetData"/>
            </Dialog>
        </div>
    </t>
`);
    registerTemplate("mrp_workorder.MrpDisplayEmployeesPanel_content", `/mrp_workorder/static/src/mrp_display/employees_panel.xml`, `<t t-name="mrp_workorder.MrpDisplayEmployeesPanel_content" xml:space="preserve">
        <ul t-if="props.employees.connected.length" class="list-group h-100 overflow-y-auto">
            <li t-foreach="props.employees.connected" t-as="employee" t-key="employee.id" class="list-group-item d-flex gap-2 py-2 cursor-pointer border-end-0 border-top-0" t-on-click="() =&gt; props.setSessionOwner(employee.id,pin)" t-att-class="{'o_admin_user': employee.id === props.employees.admin.id}">
                <img t-attf-src="/web/image/hr.employee/{{employee.id}}/avatar_128" class="o_avatar rounded-circle" t-att-class="{'opacity-50': !employee.workcenters.length and employee.id !== props.employees.admin.id}"/>
                <div class="d-flex flex-column flex-grow-1 gap-1 overflow-auto">
                    <div class="d-flex justify-content-between align-items-center gap-2">
                        <span class="fw-bold text-truncate" t-att-class="{'opacity-50': !employee.workcenters.length and employee.id !== props.employees.admin.id}" t-esc="employee.name"/>
                    </div>
                    <div t-foreach="employee.workcenters" t-as="wc" t-key="wc.id" class="d-flex justify-content-between">
                        <span t-attf-class="o_tag o_tag_color_{{wc.id % 11}} badge rounded" t-esc="wc.name"/>
                        <span class="o_tabular_nums fw-bold text-action" t-esc="Math.round(wc.duration) + '\\''"/>
                    </div>
                    <div t-if="!employee.workcenters.length" class="d-flex justify-content-between">
                        <span class="text-muted">
                            <t t-if="employee.last_active &amp;&amp; employee.id !== props.employees.admin.id">
                                Last seen <RelativeTime datetime="makeDate(employee.last_active)"/>
                            </t>
                            <t t-else="">Inactive</t>
                        </span>
                    </div>
                </div>
            </li>
        </ul>
        <div t-else="" class="d-flex justify-content-center align-items-center h-100">
            <span class="text-muted">No operators connected</span>
        </div>
    </t>

    `);
    registerTemplate("mrp_workorder.MrpDisplayEmployeesPanel", `/mrp_workorder/static/src/mrp_display/employees_panel.xml`, `<t t-name="mrp_workorder.MrpDisplayEmployeesPanel" xml:space="preserve">
        <div t-if="!ui.isSmall" class="o_search_panel o_mrp_employees_panel d-flex flex-column border-end h-100 bg-view" t-att-class="env.searchModel.searchPanelInfo.className" t-ref="root">
            <t t-call="mrp_workorder.MrpDisplayEmployeesPanel_content"/>
            <div class="p-3 w-100">
                <button class="o_edit_operators btn btn-secondary w-100" t-on-click="props.popupAddEmployee">
                Edit Operators
            </button>
            </div>
        </div>

        <t t-else="">
            <button class="o_mrp_employees_panel_btn btn btn-outline-secondary d-flex align-items-center bg-view" type="button" data-bs-toggle="offcanvas" data-bs-target="#o_employees_panel" aria-controls="o_employees_panel">
                <t t-if="props.employees.admin.name">
                    <img class="o_avatar rounded-circle me-2" t-att-src="props.employees.admin.path"/>
                    <span class="text-truncate" t-out="props.employees.admin.name"/>
                </t>
                <t t-else="">
                    <span>Choose Operator</span>
                </t>
            </button>
            <div class="o_mrp_employees_panel offcanvas offcanvas-end bg-view" tabindex="-1" id="o_employees_panel" aria-labelledby="o_mrp_employees_panel">
                <div class="offcanvas-header">
                    <h5 class="offcanvas-title" id="o_mrp_employees_panel">Operators</h5>
                    <button type="button" class="btn-close" data-bs-dismiss="offcanvas" aria-label="Close"/>
                </div>
                <div class="offcanvas-body p-0">
                    <t t-call="mrp_workorder.MrpDisplayEmployeesPanel_content"/>
                </div>
                <div class="offcanvas-footer m-3 border-top">
                    <button class="btn btn-secondary w-100" t-on-click="props.popupAddEmployee">
                        Edit Operators
                    </button>
                </div>
            </div>
        </t>
    </t>
`);
    registerTemplate("mrp_workorder.MrpDisplay", `/mrp_workorder/static/src/mrp_display/mrp_display.xml`, `<t t-name="mrp_workorder.MrpDisplay" xml:space="preserve">
        <div class="o_action o_mrp_display h-100 overflow-auto">
            <div class="d-flex py-2 px-3 bg-view border-bottom flex-wrap flex-md-nowrap" t-att-class="{'gap-1': !state.firstLoad}">
                <div class="d-flex flex-nowrap justify-content-end align-items-center gap-2 overflow-auto" t-att-class="{'flex-grow-1': !state.firstLoad}">
                    <button class="o_mrp_display_back_button o_btn_icon btn btn-secondary" t-on-click="onClickBack" t-if="displayBackButton &amp;&amp; !ui.isSmall">
                        <i class="fa fa-chevron-left" role="img"/>
                    </button>
                    <t t-if="ui.isSmall" t-call="mrp_workorder.MrpDisplay.BurgerMenu"/>
                    <ControlPanelButtons t-if="groups.workorders &amp;&amp; !state.firstLoad" productionCount="productions.length" workorders="filteredWorkorders" workcenters="state.workcenters" toggleWorkcenter="toggleWorkcenterDialog.bind(this)" selectWorkcenter="selectWorkcenter.bind(this)" activeWorkcenter="state.activeWorkcenter" relevantCount="relevantRecords.length" adminWorkorders="adminWorkorderIds" hideNewWorkcenterButton="shouldHideNewWorkcenterButton"/>
                    <MrpDisplayEmployeesPanel t-if="groups.workorders &amp;&amp; ui.isSmall &amp;&amp; !state.firstLoad" employees="useEmployee.employees" setSessionOwner.bind="useEmployee.toggleSessionOwner" popupAddEmployee.bind="popupAddEmployee"/>
                </div>
                <div class="d-flex align-items-center justify-content-end gap-2 flex-grow-1 flex-grow-md-0" t-att-class="{'flex-basis-100': ui.isSmall}">
                    <MrpDisplaySearchBar t-if="!state.firstLoad">
                        <t t-set-slot="search-bar-additional-menu" t-if="groups.workorders">
                            <div class="o_dropdown_container border-start px-3">
                                <div class="px-3 fs-5 mb-2">
                                    <i class="me-2 text-info fa fa-filter" role="img"/>
                                    <h5 class="o_dropdown_title d-inline">WO Filters</h5>
                                </div>
                                <t t-foreach="env.searchModel.state.workorderFilters" t-as="item" t-key="item.name">
                                    <CheckboxItem class="{ 'o_menu_item text-truncate': true, selected: item.isActive }" checked="item.isActive" closingMode="'none'" onSelected="() =&gt; {item.isActive = !item.isActive; this.invalidateRecordIdsCache();}" t-out="item.string"/>
                                </t>
                            </div>
                        </t>
                    </MrpDisplaySearchBar>
                    <Pager t-if="model.root.count &gt; model.root.limit &amp;&amp; !state.firstLoad" total="model.root.count" offset="model.root.offset" limit="model.root.limit" onUpdate.bind="_onPagerChanged"/>
                    <t t-if="!ui.isSmall" t-call="mrp_workorder.MrpDisplay.BurgerMenu"/>
                </div>
            </div>
            <div t-if="state.firstLoad" class="d-flex align-items-center justify-content-center overflow-hidden">
                <div class="o_mrp_display_onboarding_image position-relative">
                    <img class="position-absolute z-n1" src="/mrp_workorder/static/img/op_sidebar.png" alt="Shop Floor Onboarding Image"/>
                    <span class="o_annotation o_annotation_1 o_annotation_end position-absolute fw-bolder">Time Clock</span>
                    <span class="o_annotation o_annotation_2 o_annotation_end position-absolute fw-bolder">Quality Control</span>
                    <span class="o_annotation o_annotation_3 o_annotation_start position-absolute fw-bolder">Feedback Loop</span>
                    <span class="o_annotation o_annotation_4 o_annotation_start position-absolute fw-bolder">Register Materials</span>
                    <span class="o_annotation o_annotation_5 o_annotation_start position-absolute fw-bolder">Select Operator</span>
                </div>
                <div class="o_mrp_display_onboarding_button_container position-fixed bottom-0 w-100 text-center">
                    <button class="btn btn-lg btn-primary my-5" t-on-click="() =&gt; this.toggleWorkcenterDialog()">Activate your Work Centers</button>
                </div>
            </div>
            <main t-else="" class="o_mrp_display_content o_content o_component_with_search_panel">
                <MrpDisplayEmployeesPanel t-if="groups.workorders &amp;&amp; !ui.isSmall" employees="useEmployee.employees" setSessionOwner.bind="useEmployee.toggleSessionOwner" popupAddEmployee.bind="popupAddEmployee"/>
                <div class="o_mrp_display_records position-relative d-grid align-items-start align-content-start flex-grow-1 gap-3 p-3 h-auto h-md-100">
                <t t-foreach="relevantRecords" t-as="record" t-key="record.id">
                    <MrpDisplayRecord groups="groups" record="record" production="getProduction(record)" workcenters="state.workcenters" selectWorkcenter.bind="selectWorkcenter" updateEmployees.bind="useEmployee.getConnectedEmployees" sessionOwner="useEmployee.employees.admin" removeFromCache.bind="removeRecordIdFromCache" barcodeTarget="barcodeTargetRecord === record.resId"/>
                </t>
                <t t-if="!relevantRecords.length">
                    <t t-foreach="demoMORecords" t-as="record" t-key="record.id">
                        <MrpDisplayRecord groups="groups" record="record" production="getProduction(record)" workcenters="state.workcenters" selectWorkcenter.bind="selectWorkcenter" updateEmployees.bind="useEmployee.getConnectedEmployees" sessionOwner="useEmployee.employees.admin" removeFromCache.bind="removeRecordIdFromCache" demoRecord="true"/>
                    </t>
                    <div class="o_view_nocontent">
                        <div class="o_nocontent_help">
                            <p>
                                Shop Floor Control Panel
                            </p><p>
                                Track work orders, show instructions and record manufacturing operations from here:
                                quality control, consumed quantities, lot/serial numbers, etc.
                            </p>
                            <button role="button" class="btn btn-lg btn-primary" t-on-click="setMaxLimit" t-if="model.root.count &gt; state.limit">Load All Manufacturing Orders</button>
                            <button role="button" class="btn btn-lg btn-primary" t-on-click="loadSamples" t-if="state.canLoadSamples" t-att-disabled="state.canLoadSamples === 'disabled'">Load Samples</button>
                        </div>
                    </div>
                </t>
            </div>
            </main>
        </div>
    </t>
    `);
    registerTemplate("mrp_workorder.MrpDisplay.BurgerMenu", `/mrp_workorder/static/src/mrp_display/mrp_display.xml`, `<t t-name="mrp_workorder.MrpDisplay.BurgerMenu" xml:space="preserve">
        <div class="o_cp_burger_menu">
            <button class="o_btn_icon btn btn-light" type="button" data-bs-toggle="dropdown" aria-expanded="false">
                <i class="fa fa-navicon" role="img"/>
            </button>
            <ul class="dropdown-menu">
                <li>
                    <button class="dropdown-item py-2" t-on-click="onClickRefresh">
                        <i class="fa fa-refresh me-2" role="img"/>Reload Data
                    </button>
                </li>
                <li>
                    <a class="dropdown-item py-2" t-attf-href="/scoped_app?app_id=mrp_shop_floor&amp;path=scoped_app/shop-floor&amp;app_name={{appName}}" target="_blank">
                        <i class="fa fa-arrow-circle-down me-2" role="img"/>Install App
                    </a>
                </li>
                <li>
                    <button class="dropdown-item py-2" t-on-click="onClickBack" t-if="displayBackButton &amp;&amp; ui.isSmall">
                        <i class="fa fa-arrow-left me-2" role="img"/>
                        Back
                    </button>
                </li>
                <li>
                    <button t-if="!pwaService.isScopedApp" class="dropdown-item py-2" t-on-click="close">
                        <i class="fa fa-th me-2" role="img"/>Close
                    </button>
                </li>
            </ul>
        </div>
    </t>
`);
    registerTemplate("mrp_workorder.MrpDisplayAction", `/mrp_workorder/static/src/mrp_display/mrp_display_action.xml`, `<t t-name="mrp_workorder.MrpDisplayAction" xml:space="preserve">
        <WithSearch t-props="withSearchProps" t-slot-scope="search">
            <MrpDisplay models="models" resModel="resModel" action="props.action" context="search.context" domain="search.domain" groupBy="search.groupBy" orderBy="search.orderBy" display="search.display"/>
        </WithSearch>
    </t>
`);
    registerTemplate("mrp_workorder.MrpDisplayRecord", `/mrp_workorder/static/src/mrp_display/mrp_display_record.xml`, `<t t-name="mrp_workorder.MrpDisplayRecord" xml:space="preserve">
        <div class="o_mrp_display_record card rounded" t-att-class="cssClass">
            <div class="card-header d-flex flex-column gap-1 p-2 rounded-top" t-att-class="props.record.resModel === 'mrp.workorder' ? 'cursor-pointer' : ''" t-on-click="onClickHeader" t-att-barcode_trigger="props.barcodeTarget ? 'PAUS' : false">
                <div class="o_mrp_display_record_title o_record_name card-title d-flex justify-content-between align-items-center mb-0">
                    <h4 class="mb-0 text-wrap text-break font-monospace" t-out="props.record.resModel === 'mrp.workorder' ? record.production_id.display_name: record.display_name"/>
                    <div class="ms-auto o_mrp_display_record_assigned_users d-flex flex-wrap position-relative z-1">
                        <div t-if="showAssignedEmployees">
                            <t t-foreach="record.employee_assigned_ids.resIds" t-as="employee" t-key="employee.id">
                                <img t-attf-src="/web/image/hr.employee/{{employee}}/image_128" class="o_avatar border border-2 rounded-circle" t-att-class="{'ms-n2': !employee_first}" t-attf-style="position: relative; z-index: -{{employee_index}}"/>
                            </t>
                        </div>
                        <t t-if="!this.props.record.data.employee_ids.records.length">
                            <span t-if="props.record.resModel === 'mrp.workorder'" class="o_mrp_display_record_start_btn btn btn-outline-primary text-uppercase fw-bold lh-1 ms-auto" t-att-class="{'opacity-0': disabled}">start</span>
                            <span t-else="" class="badge rounded-pill p-2 lh-1 text-nowrap" t-att-class="{                                       'border border-info text-info': record.state === 'confirmed',                                       'border border-warning text-warning': record.state === 'progress',                                       'border border-danger text-danger': record.state === 'to_close'                                   }">
                                <SelectionField name="'state'" record="props.record" readonly="true"/>
                            </span>
                        </t>
                    </div>
                    <div t-if="this.props.record.data.employee_ids.records.length" class="d-flex gap-2 flex-wrap justify-content-end cursor-default" t-on-click="(ev) =&gt; ev.stopPropagation()">
                        <div t-if="props.record.resModel === 'mrp.workorder' and record.state === 'progress' and props.groups.timer" class="o_mrp_timer o_tabular_nums align-content-center rounded px-2 fw-bolder">
                            <MrpTimerField name="'duration'" record="props.record" readonly="true"/>
                        </div>
                        <div class="d-flex flex-wrap justify-content-end positon-relative z-1">
                            <t t-foreach="this.props.record.data.employee_ids.resIds" t-as="employee" t-key="employee">
                                <img t-attf-src="/web/image/hr.employee/{{employee}}/avatar_128" class="o_avatar border border-2 rounded-circle" t-att-class="{'ms-n2': !employee_first}" t-attf-style="position: relative; z-index: -{{employee_index}}"/>
                            </t>
                        </div>
                    </div>
                </div>
                <h5 t-if="record.name != record.display_name" class="mb-0 text-truncate fw-normal" t-out="record.name"/>
                <div class="d-flex justify-content-between align-items-end gap-1">
                    <span class="o_finished_product me-1" t-esc="record.product_id.display_name"/>
                    <div class="o_quantity">
                        <span class="text-nowrap fw-bolder" t-att-class="{'text-danger': quantityProducing &gt; quantityToProduce}">
                            <t t-esc="quantityToDisplay"/>
                        </span>
                    </div>
                </div>
                <span class="o_finished_product mt-auto mb-0"><t t-esc="record.product_description_variants"/></span>
                <div t-if="logNote" class="o_mrp_record_line d-flex justify-content-between border rounded p-2 bg-100 cursor-pointer" t-on-click="(ev) =&gt; this.editLogNote(ev)">
                    <t t-out="logNote"/>
                    <i class="ms-1 fa fa-pencil-square-o lh-base" role="img"/>
                </div>
            </div>
            <ul t-if="workorders.length" class="list-group list-group-flush border-bottom">
                <t t-foreach="workorders" t-as="workorder" t-key="workorder.data.id">
                    <MrpWorkorder t-if="workorder.data.state !== 'cancel'" t-props="subRecordProps(workorder)"/>
                </t>
            </ul>
            <ul t-if="moves.length || checks.length || byProducts.length" class="list-group list-group-flush border-top-0 py-1">
                <t t-foreach="moves" t-as="move" t-key="move.data.id">
                    <StockMove t-props="subRecordProps(move)"/>
                </t>
                <t t-foreach="checks" t-as="check" t-key="check.data.id">
                    <StockMove t-if="['register_consumed_materials', 'register_byproducts'].includes(check.data.test_type)" t-props="subRecordProps(check)"/>
                    <QualityCheck t-else="" t-props="subRecordProps(check)"/>
                </t>

                <t t-foreach="byProducts" t-as="byproductMove" t-key="byproductMove.id">
                    <StockMove t-props="subRecordProps(byproductMove)"/>
                </t>
            </ul>
            <div class="card-footer d-flex justify-content-between align-items-center border-top-0 rounded-bottom p-2 bg-view" t-att-class="{'opacity-0': disabled}">
                <t t-if="props.record.resModel === 'mrp.production'" t-call="mrp_workorder.MrpDisplayProductionFooter"/>
                <t t-if="props.record.resModel === 'mrp.workorder'" t-call="mrp_workorder.MrpDisplayWorkorderFooter"/>
                <button t-if="!state.underValidation" class="o_btn_icon btn btn-secondary ms-auto" t-on-click="onClickOpenMenu">
                    <i class="fa fa-ellipsis-v" role="img"/>
                </button>
            </div>
        </div>
    </t>

    `);
    registerTemplate("mrp_workorder.MrpDisplayProductionFooter", `/mrp_workorder/static/src/mrp_display/mrp_display_record.xml`, `<t t-name="mrp_workorder.MrpDisplayProductionFooter" xml:space="preserve">
        <t t-if="props.record.data.state === 'to_close' and (!['serial', 'lot'].includes(trackingMode) or this.props.record.data.lot_producing_ids)" t-set="_btn_type" t-value="'btn-primary'"/>
        <t t-else="" t-set="_btn_type" t-value="'btn-secondary'"/>
        <button t-if="displayDoneButton" t-attf-class="btn #{_btn_type}" t-on-click="validate" t-att-barcode_trigger="props.barcodeTarget ? 'CLMO' : false">
            <t>Close Production</t>
        </button>
    </t>
    `);
    registerTemplate("mrp_workorder.MrpDisplayWorkorderFooter", `/mrp_workorder/static/src/mrp_display/mrp_display_record.xml`, `<t t-name="mrp_workorder.MrpDisplayWorkorderFooter" xml:space="preserve">
        <t t-set="_close_production" t-value="props.production.data.picking_type_auto_close &amp;&amp; props.record.data.is_last_unfinished_wo"/>
        <t t-if="(_close_production &amp;&amp; ['serial', 'lot'].includes(trackingMode) &amp;&amp; !this.props.production.data.lot_producing_ids) || !active" t-set="_btn_type" t-value="'btn-secondary'"/>
        <t t-else="" t-set="_btn_type" t-value="'btn-primary'"/>
        <button t-if="displayDoneButton" t-attf-class="btn #{_btn_type}" t-on-click="validate" t-att-barcode_trigger="props.barcodeTarget ? (_close_production ? 'CLMO' : 'CLWO') : false">
            <t t-if="_close_production">Close Production</t>
            <t t-else="">Mark as Done</t>
        </button>
    </t>
`);
    registerTemplate("mrp_workorder.WorkOrder", `/mrp_workorder/static/src/mrp_display/mrp_record_line/mrp_workorder.xml`, `<t t-name="mrp_workorder.WorkOrder" xml:space="preserve">
        <li class="o_mrp_record_line list-group-item d-flex align-items-center cursor-pointer" t-att-class="{'o_active': active, 'disabled': !props.clickable}" t-on-click="onClick">
            <div class="d-flex align-items-center gap-2 w-100">
                <span t-if="!isComplete" t-out="workcenter.display_name" class="o_tag badge rounded flex-shrink-0" t-attf-class="o_tag_color_{{workcenter.id % 11}}"/>
                <span class="o_mrp_operation_name text-truncate" t-out="props.record.data.name"/>
            </div>
            <div class="justify-content-end w-20" t-att-class="isEmployeeAssigned and !isComplete? 'btn btn-primary':''">
                <i class="ms-auto" t-att-class="isComplete ? 'text-muted fa fa-check' : 'oi oi-chevron-right'" role="img"/>
            </div>
        </li>
    </t>
`);
    registerTemplate("mrp_workorder.QualityCheck", `/mrp_workorder/static/src/mrp_display/mrp_record_line/quality_check.xml`, `<t t-name="mrp_workorder.QualityCheck" xml:space="preserve">
        <li class="o_mrp_record_line list-group-item d-flex justify-content-between align-items-center gap-3 border-0 cursor-pointer" t-on-click="onClick">
            <span class="o_line_label text-wrap text-break" t-att-class="isComplete ? 'text-decoration-line-through opacity-25' : ''" t-out="label"/>
            <div class="d-flex align-items-center gap-1 mb-auto">

                <span t-if="showQty" t-out="showQty" class="o_line_value fw-bold text-end"/>
                <button t-if="hasInstruction" t-on-click.stop="showWorksheet" class="o_btn_icon btn btn-outline-secondary">
                    <i class="fa fa-info" role="img"/>
                </button>
                <button class="o_btn_icon btn" t-att-class="{'p-0' : showImage}" t-attf-class="{{isActive ? activeClass : 'btn-outline-secondary'}}" t-att-barcode_trigger="isActive ? barcode : false" t-att-style="showImage ? \`background: url(\${imageUrl}) no-repeat center/contain;\` : ''">
                    <i t-if="!showImage" t-att-class="icon"/>
                </button>
            </div>
        </li>
        <FileUploader t-if="props.record.data.test_type === 'picture'" acceptedFileExtensions="'image/*'" t-key="props.record.resId" onUploaded.bind="onFileUploaded">
            <t t-set-slot="toggler"><span t-ref="fileUploaderToggle" class="d-none"/></t>
        </FileUploader>
    </t>
`);
    registerTemplate("mrp_workorder.StockMove", `/mrp_workorder/static/src/mrp_display/mrp_record_line/stock_move.xml`, `<t t-name="mrp_workorder.StockMove" xml:space="preserve">
        <li class="o_mrp_record_line list-group-item d-flex justify-content-between align-items-center gap-3 cursor-pointer border-0" t-on-click="onClick">
            <span class="o_line_label text-wrap text-break" t-att-class="isComplete ? 'text-decoration-line-through opacity-25' : ''" t-out="label"/>
            <div class="d-flex align-items-center gap-1 mb-auto text-nowrap">
                <span class="o_line_value d-flex flex-column align-items-end me-1 fw-bold lh-sm" t-att-class="{                     'text-danger': quantityDone &gt; toConsumeQuantity                 }">
                    <span class="o_mrp_record_line_qty">
                        <t t-if="(quantityDone || isComplete) &amp;&amp; quantityDone !== toConsumeQuantity" t-out="quantityDone + ' / '"/>
                        <t t-out="toConsumeQuantity"/>
                    </span>
                    <span class="o_mrp_record_line_uom ms-1 small fw-normal" t-att-class="{'text-muted': !(quantityDone &gt; toConsumeQuantity)}" t-esc="uom"/>
                </span>
                <button t-if="hasInstruction" t-on-click.stop="showWorksheet" class="o_btn_icon btn btn-outline-secondary">
                        <i class="fa fa-info" role="img"/>
                </button>
                <button class="o_btn_icon btn" t-attf-class="{{props.isCurrent ? 'btn-primary' : 'btn-outline-secondary'}}">
                    <i t-attf-class="fa fa-{{icon}}" role="img"/>
                </button>
            </div>
        </li>
        <li t-foreach="visibleMoveLines" t-as="line" t-key="line.resId" t-on-click="() =&gt; this.editQuantity(line)" class="o_mrp_record_line o_mrp_record_line_indented list-group-item position-relative d-flex justify-content-between align-items-center gap-3 border-0 cursor-pointer">
            <span class="o_line_label ms-3 text-wrap text-break" t-att-class="{'text-muted': quantityDone &gt;= toConsumeQuantity}">
                <t t-if="!byproduct &amp;&amp; line.data.location_id" t-out="line.data.location_id.display_name"/>
                <t t-if="!byproduct &amp;&amp; line.data.location_id &amp;&amp; line.data.lot_id"> / </t>
                <t t-if="line.data.lot_id" t-out="line.data.lot_id.display_name"/>
            </span>
            <div class="d-flex align-items-center gap-1 mb-auto text-nowrap">
                <span class="o_line_value d-flex flex-column align-items-end me-1 fw-bold lh-sm">
                    <span class="o_mrp_record_line_qty" t-out="line.data.quantity"/>
                    <span class="o_mrp_record_line_uom small fw-normal text-muted" t-esc="uom"/>
                </span>
                <button class="o_btn_icon btn btn-outline-secondary">
                    <i class="fa fa-pencil" role="img"/>
                </button>
            </div>
        </li>
    </t>
`);
