    registerTemplate("sale_pdf_quote_builder.section", `/sale_pdf_quote_builder/static/src/js/custom_content_kanban_like_widget/custom_content_kanban_like_widget.xml`, `<t t-name="sale_pdf_quote_builder.section" xml:space="preserve">

        <t t-set="id" t-value="section.id or section.name"/>
        <div class="mb-4">
            <div class="mb-2">
                <h3 t-out="section.name"/>
                <t t-foreach="section.files" t-as="doc" t-key="id+'-button-'+doc.id">
                    <input type="checkbox" class="btn-check" t-att-id="id+'-'+doc.id" t-att-checked="doc.is_selected" t-on-click="() =&gt; {                             doc.is_selected = !doc.is_selected;                             save(id, doc.id, doc.is_selected);                         }" t-att-disabled="props.readonly"/>
                    <label class="btn btn-secondary m-1" t-att-for="id+'-'+doc.id" t-out="doc.name"/>
                </t>
            </div>
            <t t-foreach="section.files.filter(doc =&gt; doc.is_selected)" t-as="doc" t-key="id+'-'+doc.id+'-custom_form_fields'">
                <div t-if="doc.custom_form_fields.length" t-att-class="{'pb-1 mb-3 o_horizontal_separator': !doc_last}">
                    <t t-foreach="doc.custom_form_fields" t-as="formField" t-key="id+'-'+doc.id+'-custom_form_fields'+formField_index">
                        <CustomFieldCard name="formField.name" value="formField.value" onChange="(value) =&gt; { formField.value = value; this.updateJson(); }" readonly="!!props.readonly"/>
                    </t>
                </div>
            </t>
        </div>
    </t>
`);
